package com.gboard.clone

import android.content.Context
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import kotlinx.coroutines.withContext
import java.io.File
import java.util.PriorityQueue
import kotlin.math.abs

data class Prediction(
    val text: String,
    val shouldAutoCorrect: Boolean
)

class TextPredictor(private val context: Context) {

    private val trieRoot = TrieNode()
    private val bigramMap = HashMap<String, List<String>>()

    @Volatile private var isLoaded = false
    private val blockedWords = HashSet<String>()
    private val candidateWords = HashMap<String, Int>()

    // FILES
    private val userDictFile = File(context.filesDir, "user_learning.txt")
    private val blockedFile = File(context.filesDir, "blocked.txt")
    private val candidatesFile = File(context.filesDir, "candidates.txt")
    private val typoStatsFile = File(context.filesDir, "typo_stats.txt")
    private val usageStatsFile = File(context.filesDir, "usage_stats.txt")

    // STATE
    private val typoStats = HashMap<String, HashMap<String, Int>>()
    private val usageStats = HashMap<String, Long>()
    private val fileMutex = Mutex()

    private val neighbors = mapOf(
        'q' to "wa", 'w' to "qase", 'e' to "wrsd", 'r' to "etdf", 't' to "ryfg", 'y' to "tugh", 'u' to "yijh", 'i' to "uojk", 'o' to "ipkl", 'p' to "ol",
        'a' to "qwsz", 's' to "weadzx", 'd' to "ersfxc", 'f' to "rtdgcv", 'g' to "tyfhvb", 'h' to "yugjbn", 'j' to "uihknm", 'k' to "iojlm", 'l' to "opk",
        'z' to "asx", 'x' to "sdzc", 'c' to "dfxv", 'v' to "fgcb", 'b' to "ghvn", 'n' to "hjbm", 'm' to "jkn"
    )

    fun loadDictionary() {
        if (isLoaded) return
        // Use a background thread for initial loading
        Thread {
            try {
                loadUnigrams()
                loadBigrams()
                loadPersistence()
                isLoaded = true
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }.start()
    }

    private fun loadPersistence() {
        // Read-only operations don't strictly need mutex during init if single threaded logic
        if (usageStatsFile.exists()) {
            usageStatsFile.forEachLine {
                val parts = it.split(" ")
                if (parts.size >= 2) {
                    val word = parts[0]
                    val count = parts[1].toLongOrNull() ?: 0L
                    usageStats[word] = count
                    findTrieNode(word)?.apply { frequency += (count * 1000) }
                }
            }
        }

        if (blockedFile.exists()) blockedFile.forEachLine { blockedWords.add(it.trim().lowercase()) }

        if (userDictFile.exists()) {
            userDictFile.forEachLine {
                val word = it.trim()
                if (word.isNotEmpty()) insertTrie(word, Long.MAX_VALUE)
            }
        }

        if (candidatesFile.exists()) {
            candidatesFile.forEachLine {
                val parts = it.split(" ")
                if (parts.size >= 2) candidateWords[parts[0]] = parts[1].toIntOrNull() ?: 1
            }
        }

        if (typoStatsFile.exists()) {
            typoStatsFile.forEachLine {
                val parts = it.split(" ")
                if (parts.size >= 3) {
                    val typo = parts[0]
                    val correct = parts[1]
                    val count = parts[2].toIntOrNull() ?: 0
                    typoStats.getOrPut(typo) { HashMap() }[correct] = count
                }
            }
        }
    }

    suspend fun learnWord(rawWord: String) = withContext(Dispatchers.IO) {
        val word = rawWord.trim()
        if (word.isBlank()) return@withContext
        val lower = word.lowercase()

        if (blockedWords.contains(lower)) return@withContext

        val node = findTrieNode(word)
        if (node != null && node.isEndOfWord) {
            // Update usage
            usageStats[word] = usageStats.getOrDefault(word, 0L) + 1
            node.frequency += 1000
            saveUsageStats()
        } else {
            // Staged learning
            val count = candidateWords.getOrDefault(word, 0) + 1
            if (count >= 3) {
                insertTrie(word, Long.MAX_VALUE)
                fileMutex.withLock {
                     try { userDictFile.appendText("$word\n") } catch (e: Exception) {}
                }
                candidateWords.remove(word)
            } else {
                candidateWords[word] = count
            }
            saveCandidates()
        }
    }

    suspend fun removeWord(word: String) = withContext(Dispatchers.IO) {
        blockedWords.add(word.lowercase())
        fileMutex.withLock {
            try { blockedFile.writeText(blockedWords.joinToString("\n")) } catch (e: Exception) {}
        }
    }

    suspend fun learnCorrection(typo: String, correct: String) = withContext(Dispatchers.IO) {
        if (typo.isBlank() || correct.isBlank() || typo.equals(correct, true)) return@withContext
        val t = typo.lowercase()
        val map = typoStats.getOrPut(t) { HashMap() }
        map[correct] = (map[correct] ?: 0) + 1
        saveTypoStats()
    }

    private suspend fun saveUsageStats() {
        fileMutex.withLock {
            try {
                val sb = StringBuilder()
                usageStats.forEach { (w, c) -> sb.append("$w $c\n") }
                usageStatsFile.writeText(sb.toString())
            } catch (e: Exception) { e.printStackTrace() }
        }
    }

    private suspend fun saveCandidates() {
        fileMutex.withLock {
            try {
                val sb = StringBuilder()
                candidateWords.forEach { (w, c) -> sb.append("$w $c\n") }
                candidatesFile.writeText(sb.toString())
            } catch (e: Exception) { e.printStackTrace() }
        }
    }

    private suspend fun saveTypoStats() {
        fileMutex.withLock {
            try {
                val sb = StringBuilder()
                typoStats.forEach { (t, map) ->
                    map.forEach { (c, count) -> sb.append("$t $c $count\n") }
                }
                typoStatsFile.writeText(sb.toString())
            } catch (e: Exception) { e.printStackTrace() }
        }
    }

    suspend fun predict(currentInput: String, previousWord: String, isAmharic: Boolean): List<Prediction> {
        if (!isLoaded) return emptyList()
        if (isAmharic) return emptyList()

        return withContext(Dispatchers.Default) {
            if (currentInput.isBlank()) {
                val nextWords = bigramMap[previousWord.lowercase()] ?: listOf("The", "I", "Hello")
                return@withContext nextWords
                    .filter { !blockedWords.contains(it.lowercase()) }
                    .map { Prediction(it, false) }
            }

            val term = currentInput.lowercase()
            val candidates = ArrayList<SearchResult>()

            // FAT FINGER RULE: Only nearby 'I' keys, NOT numbers (8, 9 removed)
            if (term.length == 1 && "uiojkl".contains(term)) {
                candidates.add(SearchResult("I", 0.0, Long.MAX_VALUE, true))
            }

            candidates.addAll(searchPrefix(term))
            if (candidates.size < 5) {
                candidates.addAll(searchFuzzy(term))
            }

            val ranked = candidates.sortedWith(Comparator { a, b ->
                val lenDiffA = abs(a.word.length - term.length)
                val lenDiffB = abs(b.word.length - term.length)
                if (lenDiffA != lenDiffB) return@Comparator lenDiffA - lenDiffB
                if (abs(a.score - b.score) > 0.1) return@Comparator a.score.compareTo(b.score)
                b.frequency.compareTo(a.frequency)
            })
            .distinctBy { it.word }
            .filter { !blockedWords.contains(it.word.lowercase()) }
            .take(3)

            ranked.mapIndexed { index, result ->
                val isTop = index == 0
                var confident = false

                if (isTop) {
                    val lengthRatio = result.word.length.toFloat() / term.length.toFloat()
                    val isLengthSafe = if (term.length > 4) lengthRatio > 0.6f else true
                    val learnedCount = typoStats[term]?.get(result.word) ?: 0

                    if (learnedCount >= 3) {
                        confident = true
                    } else if (isLengthSafe) {
                        if (result.isPrefix) confident = true
                        else if (result.score <= term.length * 0.3) confident = true
                    }
                }
                Prediction(result.word, confident)
            }
        }
    }

    // === INTERNAL STRUCTURES ===
    data class SearchResult(val word: String, val score: Double, val frequency: Long, val isPrefix: Boolean)

    class TrieNode {
        val children = HashMap<Char, TrieNode>(4)
        var isEndOfWord = false
        var frequency: Long = 0
        var maxSubtreeFreq: Long = 0
        var word: String? = null
    }

    private fun findTrieNode(word: String): TrieNode? {
        var node = trieRoot
        for (c in word.lowercase()) node = node.children[c] ?: return null
        return node
    }

    private fun insertTrie(word: String, freq: Long) {
        var node = trieRoot
        if (freq > node.maxSubtreeFreq) node.maxSubtreeFreq = freq
        for (c in word) {
            node = node.children.getOrPut(c) { TrieNode() }
            if (freq > node.maxSubtreeFreq) node.maxSubtreeFreq = freq
        }
        node.isEndOfWord = true
        node.word = word
        if (freq > node.frequency) node.frequency = freq
    }

    private fun searchPrefix(prefix: String): List<SearchResult> {
        var node = trieRoot
        for (c in prefix) node = node.children[c] ?: return emptyList()
        val results = ArrayList<SearchResult>()
        collectDescendants(node, results)
        return results
    }

    private fun collectDescendants(node: TrieNode, results: MutableList<SearchResult>) {
        if (results.size >= 5) return
        if (node.isEndOfWord && node.word != null) {
            results.add(SearchResult(node.word!!, 0.0, node.frequency, true))
        }
        node.children.values.sortedByDescending { it.maxSubtreeFreq }.forEach {
            collectDescendants(it, results)
        }
    }

    private fun searchFuzzy(target: String): List<SearchResult> {
        val results = ArrayList<SearchResult>()
        val maxCost = if (target.length < 4) 1.5 else 3.0
        recursiveWalk(trieRoot, target, 0, 0.0, maxCost, results)
        return results
    }

    private fun recursiveWalk(node: TrieNode, target: String, index: Int, cost: Double, maxCost: Double, results: MutableList<SearchResult>) {
        if (cost > maxCost) return
        if (node.isEndOfWord && node.word != null) {
             val lenDiff = abs(node.word!!.length - target.length)
             val finalCost = cost + (lenDiff * 1.0)
             if (finalCost <= maxCost) {
                 results.add(SearchResult(node.word!!, finalCost, node.frequency, false))
             }
        }
        if (cost + 1.0 > maxCost) return

        // Insertion
        node.children.forEach { (char, child) ->
             val insCost = if (char == '\'') 0.1 else 1.0
             recursiveWalk(child, target, index, cost + insCost, maxCost, results)
        }

        if (index >= target.length) return
        val char = target[index]

        // Match/Sub
        node.children.forEach { (childChar, childNode) ->
            var newCost = cost
            if (childChar != char) {
                val nearby = neighbors[char]?.contains(childChar) == true
                newCost += if (nearby) 0.5 else 1.0
            }
            recursiveWalk(childNode, target, index + 1, newCost, maxCost, results)
        }

        // Deletion
        recursiveWalk(node, target, index + 1, cost + 1.0, maxCost, results)
    }

    private fun loadUnigrams() {
        val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
        if (resId == 0) return
        context.resources.openRawResource(resId).use { stream ->
            stream.bufferedReader().forEachLine { line ->
                val parts = line.trim().split("\\s+".toRegex())
                if (parts.isNotEmpty()) insertTrie(parts[0], if (parts.size >= 2) parts[1].toLongOrNull() ?: 100L else 100L)
            }
        }
    }

    private fun loadBigrams() {
        val tempMap = HashMap<String, PriorityQueue<Pair<Long, String>>>()
        val resId = context.resources.getIdentifier("bigrams", "raw", context.packageName)
        if (resId != 0) {
            context.resources.openRawResource(resId).use { stream ->
                stream.bufferedReader().forEachLine { line ->
                    val parts = line.trim().split(" ")
                    if (parts.size >= 3 && (parts[2].toLongOrNull() ?: 0L) > 1000) {
                        val heap = tempMap.getOrPut(parts[0].lowercase()) { PriorityQueue { a, b -> a.first.compareTo(b.first) } }
                        heap.add((parts[2].toLongOrNull() ?: 0L) to parts[1])
                        if (heap.size > 3) heap.poll()
                    }
                }
            }
        }
        tempMap.forEach { (key, heap) -> bigramMap[key] = heap.sortedByDescending { it.first }.map { it.second } }
    }
}

