private fun commit(text: String) {
    // LOGIC: Only un-suppress if we are typing actual content.
    // If we are typing a space, we consume the suppression but don't force a reset 
    // if logic elsewhere demands it (though usually space implies new word start).
    // But for clarity: Typing a character starts a new specific correction context.
    if (text.trim().isNotEmpty()) {
        isAutocorrectSuppressed = false
    }
    val ic = currentInputConnection ?: return

    // SMART PUNCTUATION HANDLING
    // If punctuation, treat as a word finisher -> Trigger Autocorrect on previous word
    if (!isAmharic && separators.contains(text) && isAutocorrectEnabled && !isAutocorrectSuppressed) {
        val rawBefore = ic.getTextBeforeCursor(50, 0)?.toString() ?: ""
        // Get the last token (ignore trailing spaces)
        val token = rawBefore.trimEnd().substringAfterLast(" ").substringAfterLast("\n")

        if (token.isNotEmpty() && currentBestPrediction != null) {
            // Check if the best prediction matches the token (ignoring case)
            // If token is "th" and pred is "the", we substitute.
            // We assume updateSuggestions() ran on the last keypress and currentBestPrediction is fresh.
            val bestPred = currentSuggestions.firstOrNull()
            if (bestPred != null && bestPred.shouldAutoCorrect && !token.equals(bestPred.text, ignoreCase = true)) {
                // Only Correct if Confident
                val replacement = bestPred.text
                ic.beginBatchEdit()
                ic.deleteSurroundingText(token.length, 0)
                ic.commitText(replacement, 1)
                ic.endBatchEdit()

                // Learn the correction
                serviceScope.launch(Dispatchers.Default) { predictor?.learnWord(replacement) }
            }
        }
    }

