private fun pickSuggestion(suggestion: String) {
    val ic = currentInputConnection ?: return
    val text = ic.getTextBeforeCursor(60, 0)?.toString() ?: ""

    // 1. Identify the visual chunk the user is currently typing
    val visualChunk = text.substringAfterLast(" ").substringAfterLast("\n")
    if (visualChunk.isEmpty()) return

    // 2. Extract Punctuation Shells
    // Example: "(workin?!"
    // Prefix: "("
    // Core: "workin"
    // Suffix: "?!"
    val prefix = visualChunk.takeWhile { !it.isLetterOrDigit() }
    val suffix = visualChunk.takeLastWhile { !it.isLetterOrDigit() }

    // 3. Extract the core typo to learn from
    // If visualChunk is "(workin?!", core is "workin"
    // We handle edge case where there is no core (just punctuation) by defaulting to empty
    val coreTypo = visualChunk.drop(prefix.length).dropLast(suffix.length)

    // 4. Construct the Replacement
    // Preserve the user's punctuation, insert the corrected word, add a space
    val commitText = "$prefix$suggestion$suffix "

    ic.beginBatchEdit()
    ic.deleteSurroundingText(visualChunk.length, 0)
    ic.commitText(commitText, 1)
    ic.endBatchEdit()

    // 5. LEARN
    serviceScope.launch(Dispatchers.Default) {
         // Boost the suggestion
         predictor?.learnWord(suggestion)
         // Learn the correction (Typos map to Correct words)
         if (coreTypo.isNotEmpty() && coreTypo != suggestion) {
             predictor?.learnCorrection(coreTypo, suggestion)
         }
    }

    updateSuggestions()
}

