// UPDATED SIGNATURE: Added 'isExplicit' to distinguish tapping vs typing
fun learnWord(rawWord: String, prev: String?, prevPrev: String?, isExplicit: Boolean) {
    val word = rawWord.trim()
    if (word.isBlank()) return
    if (blockedWords.contains(word.lowercase())) return

    val node = findTrieNode(word)

    // CASE A: Known Word (Already in Dictionary)
    // We always boost frequency/bigrams for known words, even if typed manually.
    if (node != null && node.isEndOfWord) {
        boostWordStats(word, node, prev, prevPrev)
        return
    }

    // CASE B: Unknown Word (Candidate for Learning)
    // We apply strict filters here to prevent garbage pollution.

    // 1. Garbage Filter: If it looks like trash, ignore it completely.
    if (!isValidLearningCandidate(word)) return

    // 2. Promotion Logic
    // If Explicit (User tapped suggestion): Learn immediately.
    // If Implicit (Spacebar): Require 5 occurrences.
    val threshold = if (isExplicit) 1 else 5

    val count = candidateWords.getOrDefault(word, 0) + 1
    if (count >= threshold) {
        // PROMOTE TO DICTIONARY
        insertTrie(word, Long.MAX_VALUE)
        fileMutex.withLock {
             try { userDictFile.appendText("$word\n") } catch (e: Exception) {}
        }
        candidateWords.remove(word)
        boostWordStats(word, findTrieNode(word)!!, prev, prevPrev)
    } else {
        // Keep in probation
        candidateWords[word] = count
        isDirty = true
    }
    saveCandidates()
}

private fun boostWordStats(word: String, node: TrieNode, prev: String?, prevPrev: String?) {
    // 1. Learn Unigram
    synchronized(usageStats) {
        usageStats[word] = usageStats.getOrDefault(word, 0L) + 1
        node.frequency += 1000
    }

    // 2. Learn Bigram (Prev -> Word)
    if (prev != null) {
        val k = prev.lowercase()
        synchronized(userBigrams) {
            val map = userBigrams.getOrPut(k) { HashMap() }
            map[word] = (map[word] ?: 0) + 1
        }
    }

    // 3. Learn Trigram (PrevPrev_Prev -> Word)
    if (prev != null && prevPrev != null) {
        val k = "${prevPrev.lowercase()}_${prev.lowercase()}"
        synchronized(userTrigrams) {
            val map = userTrigrams.getOrPut(k) { HashMap() }
            map[word] = (map[word] ?: 0) + 1
        }
    }
    isDirty = true
}

private fun isValidLearningCandidate(word: String): Boolean {
    // Rule 1: Too short (unless 'I' or 'a')
    if (word.length < 2 && word != "I" && word != "a") return false

    // Rule 2: Must contain at least one vowel (prevents 'sdfgh')
    // We allow 'y' as a vowel here.
    val hasVowel = word.contains(Regex("[aeiouyAEIOUY]"))
    if (!hasVowel) return false

    // Rule 3: Detect accidental internal capitalization (e.g. "tHis")
    // Valid: "McDonald" (Starts with Upper, 3rd is Upper)
    // Invalid: "lIke" (Starts with Lower, has Upper)
    val firstLower = word[0].isLowerCase()
    val hasUpperLater = word.substring(1).any { it.isUpperCase() }
    if (firstLower && hasUpperLater) return false

