    // --- AMHARIC LOGIC LAYER ---
    loadAmharicNeighbors(this)
}

private fun loadAmharicNeighbors(map: HashMap<Char, String>) {
    // HELPER: Bidirectional mapping (a neighbor of b, b neighbor of a)
    fun link(chars: String) {
        for (c1 in chars) {
            val sb = StringBuilder(map[c1] ?: "")
            for (c2 in chars) {
                if (c1 != c2 && !sb.contains(c2)) sb.append(c2)
            }
            map[c1] = sb.toString()
        }
    }

    // 1. HOMOPHONES (Sound-Alikes)
    // Corrects spelling errors like ሠላም -> ሰላም
    // We map all 7 vowel orders for the major collision groups.

    // Group H: ሀ vs ሐ vs ኀ vs ኸ
    link("ሀሐኀኸ"); link("ሁሑኁኹ"); link("ሂሒኂኺ"); link("ሃሓኃኻ"); link("ሄሔኄኼ"); link("ህሕኅኽ"); link("ሆሖኆኾ")

    // Group S: ሰ vs ሠ
    link("ሰሠ"); link("ሱሡ"); link("ሲሢ"); link("ሳሣ"); link("ሴሤ"); link("ስሥ"); link("ሶሦ")

    // Group A: አ vs ዐ
    link("አዐ"); link("ኡዑ"); link("ኢዒ"); link("ኣዓ"); link("ኤዔ"); link("እዕ"); link("ኦዖ")

    // Group TS: ጸ vs ፀ
    link("ጸፀ"); link("ጹፁ"); link("ጺፂ"); link("ጻፃ"); link("ጼፄ"); link("ጽፅ"); link("ጾፆ")

    // 2. QWERTY SPATIAL MAPPING (Transliteration 'Fat Finger')
    // Maps Amharic chars based on their Latin key proximity.
    // e.g. 's'(ሰ) is next to 'd'(ደ). If user types 'ደ' they might mean 'ሰ'.
    // We map the Base Forms (1st order) which covers 80% of errors.

    link("ሰደዘአ"); // s-d-z-a (s neighbors)
    link("ሀጀገበ"); // h-j-g-b
    link("ቀወአ");   // q-w-a
    link("ረተደፈ"); // r-t-d-f
    link("ተየፈገ"); // t-y-f-g
    link("ከኢኦጀ"); // k-i-o-j
    link("ነበሀጀመ"); // n-b-h-j-m
}

