package com.gboard.clone

import android.content.Context
import kotlinx.coroutines.Dispatchers
import kotlinx.coroutines.withContext
import kotlinx.coroutines.sync.Mutex
import kotlinx.coroutines.sync.withLock
import java.io.File
import java.util.PriorityQueue
import kotlin.math.abs

data class Prediction(
    val text: String,
    val shouldAutoCorrect: Boolean
)

class TextPredictor(private val context: Context) {

    // DATA STRUCTURES
    private val trieRoot = TrieNode()
    private val bigramMap = HashMap<String, List<String>>() // Static Bigrams

    // DYNAMIC LEARNING MEMORY
    private val userBigrams = HashMap<String, HashMap<String, Int>>() // "New" -> {"York": 5}
    private val userTrigrams = HashMap<String, HashMap<String, Int>>() // "I am" -> {"happy": 2}

    @Volatile private var isLoaded = false
    @Volatile private var isDirty = false

    private val blockedWords = HashSet<String>()
    private val candidateWords = HashMap<String, Int>()

    // FILES
    private val userDictFile = File(context.filesDir, "user_learning.txt")
    private val bigramFile = File(context.filesDir, "user_bigrams.txt")
    private val trigramFile = File(context.filesDir, "user_trigrams.txt")
    private val blockedFile = File(context.filesDir, "blocked.txt")
    private val candidatesFile = File(context.filesDir, "candidates.txt")
    private val typoStatsFile = File(context.filesDir, "typo_stats.txt")
    private val usageStatsFile = File(context.filesDir, "usage_stats.txt")

    // STATE
    private val typoStats = HashMap<String, HashMap<String, Int>>()
    private val usageStats = HashMap<String, Long>()
    private val fileMutex = Mutex()

    // ADVANCED SPATIAL & PHONETIC MAP
    private val neighbors = HashMap<Char, String>().apply {
        // --- LATIN QWERTY LAYER ---
        put('q', "wsa12"); put('w', "qeasd23"); put('e', "wrsdf34"); put('r', "etdfg45"); put('t', "ryfgh56")
        put('y', "tughj67"); put('u', "yijhk78"); put('i', "uojkl89"); put('o', "ipkl90"); put('p', "ol0")
        put('a', "qwsz"); put('s', "weadzxc"); put('d', "ersfxcv"); put('f', "rtdgcvb"); put('g', "tyfhvbn")
        put('h', "yugjbnm"); put('j', "uihknm"); put('k', "iojlm"); put('l', "opk")
        put('z', "asx"); put('x', "sdzc"); put('c', "dfxv"); put('v', "fgcb"); put('b', "ghvn"); put('n', "hjbm"); put('m', "jkn")
    }

    fun loadDictionary() {
        if (isLoaded) return
        Thread {
            try {
                loadAmharicNeighbors(neighbors) // Hydrate map
                loadUnigrams()
                loadCommonContractions()
                loadAmharicJson()
                loadBigrams()
                loadPersistence()
                isLoaded = true
                startAutoSave()
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }.start()
    }

    private fun startAutoSave() {
        Thread {
            while (true) {
                try {
                    Thread.sleep(30_000)
                    if (isDirty) saveData()
                } catch (e: InterruptedException) { break }
            }
        }.start()
    }

    fun flush() {
        if (isDirty) {
            Thread { saveData() }.start()
        }
    }

    // =======================================================
    // CORE PREDICTION LOGIC
    // =======================================================

    suspend fun predict(currentInput: String, prev: String, prevPrev: String, isAmharic: Boolean): List<Prediction> {
        if (!isLoaded) return emptyList()

        return withContext(Dispatchers.Default) {
            // STRATEGY: Trigrams (Highest) -> Dynamic Bigrams -> Static Bigrams -> Unigrams

            if (currentInput.isBlank()) {
                val candidates = ArrayList<String>()

                // 1. Try Trigram
                val triKey = "${prevPrev.lowercase()}_${prev.lowercase()}"
                userTrigrams[triKey]?.entries?.sortedByDescending { it.value }?.take(2)?.forEach { candidates.add(it.key) }

                // 2. Try Dynamic Bigram
                userBigrams[prev.lowercase()]?.entries?.sortedByDescending { it.value }?.take(2)?.forEach { candidates.add(it.key) }

                // 3. Fallback Static Bigram
                val static = bigramMap[prev.lowercase()] ?: emptyList()
                candidates.addAll(static.take(3))

                // 4. Zero-State Fallback
                if (candidates.isEmpty()) {
                    if (isAmharic) {
                        candidates.addAll(listOf("ሰላም", "ነው", "እንዴት"))
                    } else {
                        candidates.addAll(listOf("The", "I", "Hello"))
                    }
                }

                return@withContext candidates.distinct().take(3).map { Prediction(it, false) }
            }

            val term = currentInput.lowercase()
            val candidates = ArrayList<SearchResult>()

            // FAT FINGER RULE: Only nearby 'I' keys.
            if (term.length == 1 && "uiojkl".contains(term)) {
                candidates.add(SearchResult("I", 0.0, Long.MAX_VALUE, true))
            }

            candidates.addAll(searchPrefix(term))
            if (candidates.size < 5) {
                candidates.addAll(searchFuzzy(term))
            }

            val whitelist = setOf("I", "a", "A", "&")

            val ranked = candidates.sortedWith(Comparator { a, b ->
                // 1. Score (Lower is better)
                if (abs(a.score - b.score) > 0.01) return@Comparator a.score.compareTo(b.score)
                // 2. Frequency (Higher is better)
                if (a.frequency != b.frequency) return@Comparator b.frequency.compareTo(a.frequency)
                // 3. Length Diff
                val lenDiffA = abs(a.word.length - term.length)
                val lenDiffB = abs(b.word.length - term.length)
                lenDiffA - lenDiffB
            })
            .distinctBy { it.word }
            .filter { !blockedWords.contains(it.word.lowercase()) }
            .filter { it.word.length > 1 || whitelist.contains(it.word) || isAmharicChar(it.word) }
            .take(3)

            ranked.mapIndexed { index, result ->
                val isTop = index == 0
                var confident = false

                if (isTop) {
                    val lengthRatio = result.word.length.toFloat() / term.length.toFloat()
                    val isLengthSafe = lengthRatio >= 0.5f
                    val learnedCount = typoStats[term]?.get(result.word) ?: 0

                    if (learnedCount >= 3) {
                        confident = true
                    } else if (isLengthSafe) {
                        if (result.isPrefix) {
                             confident = true
                        } else {
                             val maxAllowedCost = term.length * 0.3
                             if (result.score <= maxAllowedCost) {
                                 confident = true
                             }
                        }
                    }
                }
                Prediction(result.word, confident)
            }
        }
    }

    // =======================================================
    // LEARNING LOGIC
    // =======================================================

    fun learnWord(rawWord: String, prev: String?, prevPrev: String?, isExplicit: Boolean) {
        val word = rawWord.trim()
        if (word.isBlank()) return
        if (blockedWords.contains(word.lowercase())) return

        val node = findTrieNode(word)

        // CASE A: Known Word
        if (node != null && node.isEndOfWord) {
            boostWordStats(word, node, prev, prevPrev)
            return
        }

        // CASE B: Unknown Word
        if (!isValidLearningCandidate(word)) return

        val threshold = if (isExplicit) 1 else 5
        val count = candidateWords.getOrDefault(word, 0) + 1

        if (count >= threshold) {
            // PROMOTE
            insertTrie(word, Long.MAX_VALUE)
            Thread {
                 fileMutex.withLockSafely {
                     try { userDictFile.appendText("$word\n") } catch (e: Exception) {}
                 }
            }.start()
            candidateWords.remove(word)
            findTrieNode(word)?.let { boostWordStats(word, it, prev, prevPrev) }
        } else {
            candidateWords[word] = count
            isDirty = true
        }
        saveCandidates()
    }

    private fun boostWordStats(word: String, node: TrieNode, prev: String?, prevPrev: String?) {
        synchronized(usageStats) {
            val newCount = usageStats.getOrDefault(word, 0L) + 1
            usageStats[word] = newCount
            node.frequency += 1000
            updatePathMaxFreq(word, node.frequency)
        }

        if (prev != null) {
            val k = prev.lowercase()
            synchronized(userBigrams) {
                val map = userBigrams.getOrPut(k) { HashMap() }
                map[word] = (map[word] ?: 0) + 1
            }
        }

        if (prev != null && prevPrev != null) {
            val k = "${prevPrev.lowercase()}_${prev.lowercase()}"
            synchronized(userTrigrams) {
                val map = userTrigrams.getOrPut(k) { HashMap() }
                map[word] = (map[word] ?: 0) + 1
            }
        }
        isDirty = true
    }

    suspend fun removeWord(word: String) = withContext(Dispatchers.IO) {
        blockedWords.add(word.lowercase())
        fileMutex.withLockSafely {
            try { blockedFile.writeText(blockedWords.joinToString("\n")) } catch (e: Exception) {}
        }
    }

    suspend fun learnCorrection(typo: String, correct: String) = withContext(Dispatchers.IO) {
        if (typo.isBlank() || correct.isBlank() || typo.equals(correct, true)) return@withContext
        val t = typo.lowercase()
        val map = typoStats.getOrPut(t) { HashMap() }
        map[correct] = (map[correct] ?: 0) + 1
        saveTypoStats()
    }

    // =======================================================
    // VALIDATION & HELPERS
    // =======================================================

    fun isValidWord(rawWord: String): Boolean {
        if (rawWord.isBlank()) return false
        val lower = rawWord.lowercase()
        if (blockedWords.contains(lower)) return false
        val node = findTrieNode(rawWord)
        return node != null && node.isEndOfWord
    }

    private fun isValidLearningCandidate(word: String): Boolean {
        val isAmharic = word.any { it.code in 0x1200..0x137F }
        if (!isAmharic && word.length < 2 && word != "I" && word != "a") return false

        val hasVowel = word.contains(Regex("[aeiouyAEIOUY]"))
        if (!isAmharic && !hasVowel) return false

        val firstLower = word[0].isLowerCase()
        val hasUpperLater = word.substring(1).any { it.isUpperCase() }
        if (firstLower && hasUpperLater) return false

        return true
    }

    private fun isAmharicChar(text: String): Boolean {
        return text.any { it.code in 0x1200..0x137F }
    }

    // =======================================================
    // SEARCH ALGORITHMS
    // =======================================================

    private fun searchPrefix(prefix: String): List<SearchResult> {
        var node = trieRoot
        for (c in prefix) node = node.children[c] ?: return emptyList()
        val results = ArrayList<SearchResult>()
        collectDescendants(node, results)
        return results
    }

    private fun collectDescendants(node: TrieNode, results: MutableList<SearchResult>) {
        if (results.size >= 5) return
        if (node.isEndOfWord && node.word != null) {
            results.add(SearchResult(node.word!!, 0.0, node.frequency, true))
        }
        node.children.values.sortedByDescending { it.maxSubtreeFreq }.forEach {
            collectDescendants(it, results)
        }
    }

    private fun searchFuzzy(target: String): List<SearchResult> {
        val results = ArrayList<SearchResult>()
        val maxCost = if (target.length < 4) 1.5 else 3.0
        recursiveWalk(trieRoot, target, 0, 0.0, maxCost, results)
        return results
    }

    private fun recursiveWalk(node: TrieNode, target: String, index: Int, cost: Double, maxCost: Double, results: MutableList<SearchResult>) {
        if (cost > maxCost) return

        if (node.isEndOfWord && node.word != null) {
             val remaining = target.length - index
             val finalCost = cost + (remaining * 1.0)
             if (finalCost <= maxCost) {
                 results.add(SearchResult(node.word!!, finalCost, node.frequency, false))
             }
        }

        if (cost + 0.1 > maxCost) return

        // TRANSPOSITION ("teh" -> "the")
        if (index < target.length - 1) {
            val char1 = target[index]
            val char2 = target[index + 1]
            val child2 = node.children[char2]
            if (child2 != null) {
                val grandChild = child2.children[char1]
                if (grandChild != null) {
                    recursiveWalk(grandChild, target, index + 2, cost + 0.75, maxCost, results)
                }
            }
        }

        // INSERTION
        node.children.forEach { (trieChar, childNode) ->
             val insCost = if (trieChar == '\'') 0.1 else 1.0
             recursiveWalk(childNode, target, index, cost + insCost, maxCost, results)
        }

        if (index >= target.length) return
        val inputChar = target[index]

        // MATCH / SUB
        node.children.forEach { (trieChar, childNode) ->
            var newCost = cost
            if (trieChar != inputChar) {
                val nearby = neighbors[inputChar]?.contains(trieChar) == true
                newCost += if (nearby) 0.25 else 1.0
            }
            recursiveWalk(childNode, target, index + 1, newCost, maxCost, results)
        }

        // DELETION
        var delCost = 1.0
        if (index > 0 && inputChar == target[index - 1]) delCost = 0.2
        recursiveWalk(node, target, index + 1, cost + delCost, maxCost, results)
    }

    // =======================================================
    // TRIE & IO
    // =======================================================

    class TrieNode {
        val children = HashMap<Char, TrieNode>(4)
        var isEndOfWord = false
        var frequency: Long = 0
        var maxSubtreeFreq: Long = 0
        var word: String? = null
    }

    data class SearchResult(val word: String, val score: Double, val frequency: Long, val isPrefix: Boolean)

    private fun findTrieNode(word: String): TrieNode? {
        var node = trieRoot
        for (c in word.lowercase()) node = node.children[c] ?: return null
        return node
    }

    private fun insertTrie(word: String, freq: Long) {
        val lower = word.lowercase()
        var node = trieRoot
        if (freq > node.maxSubtreeFreq) node.maxSubtreeFreq = freq
        for (c in lower) {
            node = node.children.getOrPut(c) { TrieNode() }
            if (freq > node.maxSubtreeFreq) node.maxSubtreeFreq = freq
        }
        node.isEndOfWord = true
        node.word = word
        if (freq > node.frequency) node.frequency = freq
    }

    private fun updatePathMaxFreq(word: String, newFreq: Long) {
        val lower = word.lowercase()
        var curr = trieRoot
        if (newFreq > curr.maxSubtreeFreq) curr.maxSubtreeFreq = newFreq
        for (c in lower) {
            curr = curr.children[c] ?: break
            if (newFreq > curr.maxSubtreeFreq) curr.maxSubtreeFreq = newFreq
        }
    }

    private fun loadUnigrams() {
        val resId = context.resources.getIdentifier("dictionary", "raw", context.packageName)
        if (resId == 0) return
        context.resources.openRawResource(resId).use { stream ->
            stream.bufferedReader().forEachLine { line ->
                val parts = line.trim().split("\\s+".toRegex())
                if (parts.isNotEmpty()) insertTrie(parts[0], if (parts.size >= 2) parts[1].toLongOrNull() ?: 100L else 100L)
            }
        }
    }

    private fun loadAmharicJson() {
        try {
            val resId = context.resources.getIdentifier("amharic_dict", "raw", context.packageName)
            if (resId != 0) {
                context.resources.openRawResource(resId).use { stream ->
                    val jsonStr = stream.bufferedReader().use { it.readText() }
                    if (jsonStr.trim().startsWith("[")) {
                        val array = org.json.JSONArray(jsonStr)
                        for (i in 0 until array.length()) {
                            val obj = array.getJSONObject(i)
                            val word = obj.optString("word")
                            val freq = obj.optLong("freq", 5000L)
                            if (word.isNotEmpty()) insertTrie(word, freq)
                        }
                    }
                }
            }
        } catch (e: Exception) { e.printStackTrace() }
    }

    private fun loadCommonContractions() {
        val contractions = listOf(
            "don't", "can't", "won't", "it's", "I'm", "I'll", "I've", "I'd",
            "that's", "didn't", "doesn't", "isn't", "aren't", "wasn't", "weren't",
            "hasn't", "haven't", "hadn't", "wouldn't", "shouldn't", "couldn't",
            "we're", "they're", "you're", "let's", "what's", "here's", "there's",
            "who's", "ain't", "y'all", "ma'am", "o'clock", "mustn't", "shan't"
        )
        contractions.forEach { insertTrie(it, Long.MAX_VALUE) }
    }

    private fun loadBigrams() {
        val resId = context.resources.getIdentifier("bigrams", "raw", context.packageName)
        if (resId != 0) {
            context.resources.openRawResource(resId).use { stream ->
                stream.bufferedReader().forEachLine { line ->
                    val parts = line.trim().split(" ")
                    if (parts.size >= 3) {
                         val queue = bigramMap.getOrPut(parts[0].lowercase()) { ArrayList() } as ArrayList
                         if (queue.size < 3) queue.add(parts[1])
                    }
                }
            }
        }
    }

    private fun loadPersistence() {
        try {
            if (bigramFile.exists()) bigramFile.forEachLine {
                val p = it.split(" ")
                if (p.size >= 3) userBigrams.getOrPut(p[0]) { HashMap() }[p[1]] = p[2].toIntOrNull() ?: 1
            }
            if (trigramFile.exists()) trigramFile.forEachLine {
                val p = it.split(" ")
                if (p.size >= 3) userTrigrams.getOrPut(p[0]) { HashMap() }[p[1]] = p[2].toIntOrNull() ?: 1
            }
            if (usageStatsFile.exists()) usageStatsFile.forEachLine {
                val p = it.split(" ")
                if (p.size >= 2) {
                    val w = p[0]
                    val c = p[1].toLongOrNull() ?: 0L
                    usageStats[w] = c
                    findTrieNode(w)?.apply { 
                        frequency += (c * 1000) 
                        updatePathMaxFreq(w, frequency)
                    }
                }
            }
            if (blockedFile.exists()) blockedFile.forEachLine { blockedWords.add(it.trim().lowercase()) }
            if (candidatesFile.exists()) candidatesFile.forEachLine { 
                val p = it.split(" ")
                if (p.size >= 2) candidateWords[p[0]] = p[1].toIntOrNull() ?: 1
            }
            if (typoStatsFile.exists()) typoStatsFile.forEachLine { 
                val p = it.split(" ")
                if (p.size >= 3) typoStats.getOrPut(p[0]) { HashMap() }[p[1]] = p[2].toIntOrNull() ?: 0
            }
        } catch(e: Exception) { e.printStackTrace() }
    }

    private fun saveData() {
        try {
             val sb = StringBuilder()
             synchronized(userBigrams) {
                 userBigrams.forEach { (k, v) -> v.forEach { (w, c) -> sb.append("$k $w $c\n") } }
             }
             bigramFile.writeText(sb.toString())

             sb.setLength(0)
             synchronized(userTrigrams) {
                 userTrigrams.forEach { (k, v) -> v.forEach { (w, c) -> sb.append("$k $w $c\n") } }
             }
             trigramFile.writeText(sb.toString())

             sb.setLength(0)
             synchronized(usageStats) {
                 usageStats.forEach { (w, c) -> sb.append("$w $c\n") }
             }
             usageStatsFile.writeText(sb.toString())

             isDirty = false
        } catch(e: Exception) { e.printStackTrace() }
    }

    private fun saveCandidates() {
        Thread {
             fileMutex.withLockSafely {
                 val sb = StringBuilder()
                 candidateWords.forEach { (w, c) -> sb.append("$w $c\n") }
                 try { candidatesFile.writeText(sb.toString()) } catch(e:Exception){}
             }
        }.start()
    }

    private fun saveTypoStats() {
        Thread {
            fileMutex.withLockSafely {
                val sb = StringBuilder()
                typoStats.forEach { (t, m) -> m.forEach { (c, n) -> sb.append("$t $c $n\n") } }
                try { typoStatsFile.writeText(sb.toString()) } catch(e:Exception){}
            }
        }.start()
    }

    private fun loadAmharicNeighbors(map: HashMap<Char, String>) {
        fun link(chars: String) {
            for (c1 in chars) {
                val sb = StringBuilder(map[c1] ?: "")
                for (c2 in chars) if (c1 != c2 && !sb.contains(c2)) sb.append(c2)
                map[c1] = sb.toString()
            }
        }
        link("ሀሐኀኸ"); link("ሁሑኁኹ"); link("ሂሒኂኺ"); link("ሃሓኃኻ"); link("ሄሔኄኼ"); link("ህሕኅኽ"); link("ሆሖኆኾ")
        link("ሰሠ"); link("ሱሡ"); link("ሲሢ"); link("ሳሣ"); link("ሴሤ"); link("ስሥ"); link("ሶሦ")
        link("አዐ"); link("ኡዑ"); link("ኢዒ"); link("ኣዓ"); link("ኤዔ"); link("እዕ"); link("ኦዖ")
        link("ጸፀ"); link("ጹፁ"); link("ጺፂ"); link("ጻፃ"); link("ጼፄ"); link("ጽፅ"); link("ጾፆ")
        link("ሰደዘአ"); link("ሀጀገበ"); link("ቀወአ"); link("ረተደፈ"); link("ተየፈገ"); link("ከኢኦጀ"); link("ነበሀጀመ")
    }

    // EXTENSION HELPER to handle compilation issues with Mutex in simple thread
    private fun Mutex.withLockSafely(action: () -> Unit) {
         // In a real coroutine env we use withLock, but here we can just use runBlocking or just ignore safety for raw threads
         // For simplicity/compilation in this specific context where we mix Threads and Coroutines:
         kotlinx.coroutines.runBlocking {
             this@withLockSafely.withLock {
                 action()
             }
         }
    }
}

