private fun commit(text: String) {
    val ic = currentInputConnection ?: return

    // RESET STATE ON NEW INPUT
    // If we are typing a real character (not space), we reset the suppression flag
    // and invalidate the 'Undo' history for autocorrect. You can only undo immediately.
    if (text.trim().isNotEmpty()) {
        isAutocorrectSuppressed = false
        lastAutocorrect = null
    }

    // [REMOVED] Punctuation Auto-Correct Logic
    // User Preference: Punctuation should strictly commit the punctuation mark,
    // never trigger a word replacement. AC is now Space-exclusive.

    if (isAmharic) {
