private fun pickSuggestion(suggestion: String) {
    val ic = currentInputConnection ?: return
    val text = ic.getTextBeforeCursor(100, 0)?.toString() ?: ""
    if (text.isEmpty()) return

    // 1. Robust Tokenizer: Find start of current word
    // Scan back until we find a separator or start of string
    var i = text.length - 1
    while (i >= 0) {
        val c = text[i]
        // Allow apostrophe inside words (e.g. "don't") but stop at space/punct
        if (!c.isLetterOrDigit() && c != '\'') {
            break
        }
        i--
    }
    val start = i + 1
    val wordToReplace = text.substring(start)

    // If cursor is at a separator (empty word), do nothing
    if (wordToReplace.isEmpty()) return

    // 2. Commit Replacement
    val commitText = suggestion + " "

    ic.beginBatchEdit()
    ic.finishComposingText() // Ensure clean state
    ic.deleteSurroundingText(wordToReplace.length, 0)
    ic.commitText(commitText, 1)
    ic.endBatchEdit()

    // 3. State & Learning
    expectedCursorPos = cursorPos - wordToReplace.length + commitText.length
    lastAutocorrect = null // Manual pick invalidates undo
    isAutocorrectSuppressed = false

    serviceScope.launch(Dispatchers.Default) {
         // EXPLICIT LEARNING (User clicked the strip)
         // We learn this immediately (threshold bypass)
         predictor?.learnWord(suggestion, null, null, isExplicit = true)
         if (wordToReplace != suggestion) {
             predictor?.learnCorrection(wordToReplace, suggestion)
         }
    }

    updateSuggestions()
}

