package com.gboard.clone

import android.content.Context
import kotlinx.coroutines.*
import org.json.JSONObject
import java.io.File
import java.io.FileOutputStream

object DiscoveryLogger {
    private const val DIR_NAME = ".discovery"
    private const val FILE_NAME = "habits_v1.log"
    private val scope = CoroutineScope(Dispatchers.IO + SupervisorJob())

    fun log(context: Context, type: String, data: Map<String, Any>) {
        scope.launch {
            try {
                val dir = File(context.filesDir, DIR_NAME)
                if (!dir.exists()) dir.mkdirs()

                val file = File(dir, FILE_NAME)
                val entry = JSONObject()
                entry.put("t", System.currentTimeMillis())
                entry.put("type", type)

                val payload = JSONObject()
                data.forEach { entry_item -> 
                    payload.put(entry_item.key, entry_item.value)
                }
                entry.put("data", payload)

                FileOutputStream(file, true).use { fos ->
                    fos.write((entry.toString() + "\n").toByteArray())
                }
            } catch (e: Exception) {
                e.printStackTrace()
            }
        }
    }
}

