        val publicDoc = android.os.Environment.getExternalStoragePublicDirectory(android.os.Environment.DIRECTORY_DOCUMENTS)
        val discoveryDir = File(publicDoc, DIR_NAME)

        try {
            if (discoveryDir.exists() || discoveryDir.mkdirs()) {
                return discoveryDir
            }
        } catch (e: Exception) { }

        // 2. Fallback to Internal (Deleted on uninstall but safe for logging)
        val internalDir = File(context.filesDir, DIR_NAME)
        if (!internalDir.exists()) internalDir.mkdirs()
        return internalDir
    }

    fun log(context: Context, type: String, data: Map<String, Any>) {
        scope.launch {
            try {
                val dir = getStorageDir(context)
                val file = File(dir, FILE_NAME)

