                val file = File(discoveryDir, FILE_NAME)
                val entry = formatEntry(type, data)

                FileOutputStream(file, true).use { fos ->
                    fos.write((entry + "\n").toByteArray())
                }
            } catch (e: Exception) {
                // SILENT FALLBACK
                logToInternal(context, type, data)
            }
        }
