private fun loadAmharicJson() {
    try {
        val resId = context.resources.getIdentifier("amharic_dict", "raw", context.packageName)
        if (resId != 0) {
            context.resources.openRawResource(resId).use { stream ->
                val jsonStr = stream.bufferedReader().use { it.readText() }
                val trimmed = jsonStr.trim()

                // Helper to process the array regardless of source
                fun parseArray(array: org.json.JSONArray) {
                    for (i in 0 until array.length()) {
                        val obj = array.getJSONObject(i)
                        val word = obj.optString("word")
                        // Support both 'freq' and 'frequency' keys
                        val freq = obj.optLong("frequency", obj.optLong("freq", 5000L))
                        if (word.isNotEmpty()) insertTrie(word, freq)
                    }
                }

                if (trimmed.startsWith("[")) {
                    parseArray(org.json.JSONArray(trimmed))
                } else if (trimmed.startsWith("{")) {
                    val root = org.json.JSONObject(trimmed)
                    if (root.has("words")) {
                        parseArray(root.getJSONArray("words"))
                    }
                }
            }
        }
    } catch (e: Exception) {
        e.printStackTrace()
    }
}

