private fun loadAmharicJson() {
    try {
        DebugBuffer.log("Predictor", "Loading Amharic JSON...")
        val resId = context.resources.getIdentifier("amharic_dict", "raw", context.packageName)
        if (resId != 0) {
            context.resources.openRawResource(resId).use { inputStream ->
                // Use STREAMING parser to avoid OOM on large dictionaries
                val reader = android.util.JsonReader(inputStream.bufferedReader())
                reader.isLenient = true
                var count = 0

                try {
                    // Handle both array root [...] or object root { "words": ... }
                    var insideWordsArray = false

                    if (reader.peek() == android.util.JsonToken.BEGIN_OBJECT) {
                        reader.beginObject()
                        while (reader.hasNext()) {
                            val name = reader.nextName()
                            if (name == "words") {
                                reader.beginArray()
                                insideWordsArray = true
                                break
                            } else {
                                reader.skipValue()
                            }
                        }
                    } else if (reader.peek() == android.util.JsonToken.BEGIN_ARRAY) {
                        reader.beginArray()
                        insideWordsArray = true
                    }

                    if (insideWordsArray) {
                        while (reader.hasNext()) {
                            reader.beginObject()
                            var word = ""
                            var freq = 5000L
                            while (reader.hasNext()) {
                                when (reader.nextName()) {
                                    "word" -> word = reader.nextString()
                                    "freq", "frequency" -> freq = reader.nextLong()
                                    else -> reader.skipValue()
                                }
                            }
                            reader.endObject()

                            if (word.isNotEmpty()) {
                                insertTrie(word, freq)
                                count++
                            }
                        }
                        reader.endArray()
                    }
                    DebugBuffer.log("Predictor", "Loaded \$count words from Amharic dictionary")
                } catch (e: Exception) {
                    DebugBuffer.log("Predictor", "JSON Error: \${e.message}")
                    e.printStackTrace()
                } finally {
                    try { reader.close() } catch (e: Exception) {}
                }
            }
        } else {
            DebugBuffer.log("Predictor", "amharic_dict.json not found in raw resources")
        }
    } catch (e: Exception) {
        DebugBuffer.log("Predictor", "Critical Load Error: \${e.message}")
        e.printStackTrace()
    }
}

