package com.gboard.clone

import java.text.SimpleDateFormat
import java.util.Date
import java.util.Locale
import java.util.concurrent.ConcurrentLinkedDeque

object DebugLogger {
    private const val MAX_LOGS = 500
    private val logBuffer = ConcurrentLinkedDeque<String>()
    private val dateFormat = SimpleDateFormat("HH:mm:ss.SSS", Locale.US)

    fun log(tag: String, message: String) {
        val timestamp = dateFormat.format(Date())
        val entry = "[$timestamp] [$tag] $message"

        logBuffer.addFirst(entry)

        // Maintain buffer size
        if (logBuffer.size > MAX_LOGS) {
            logBuffer.pollLast()
        }

        // Also print to System Logcat for Android Studio debugging
        android.util.Log.d("GboardClone", "$tag: $message")
    }

    fun getLogs(): String {
        return logBuffer.joinToString("\n")
    }

    fun clear() {
        logBuffer.clear()
    }
}

