import android.widget.TextView
import androidx.preference.PreferenceManager
import java.text.SimpleDateFormat
import java.util.Date
import android.graphics.Typeface
import android.graphics.PorterDuff
import android.graphics.PorterDuffColorFilter
import android.graphics.Color
import androidx.core.content.res.ResourcesCompat
import kotlinx.coroutines.*

class KeyboardService : InputMethodService() {

    // STATE
    private var currentLayoutView: View? = null
    private var isCaps = false
    private var isCapsLocked = false
    private var isHapticEnabled = true
    private var isSoundEnabled = false
    private var isNumberRowEnabled = false
    private var isPopupEnabled = true
    private var isOneHanded = false
    private var isDarkTheme = true
    private var cursorPos = 0
    private var keyboardHeightPercent = 100
    private var lastTouchX = 0f
    private var lastSpaceTime = 0L

    // PREDICTION
    private var predictor: TextPredictor? = null

    // DEBUG
    // Logging StringBuilder for debugging purposes
    private val debugLog = StringBuilder()

    // OPTIMIZATION: Coroutine Scope & View Caching
    private val serviceScope = CoroutineScope(Dispatchers.Main + Job())
    private var mainKeyboardCache: View? = null
    private var symbolKeyboardCache: View? = null
    private var searchJob: Job? = null
    // AMHARIC STATE
    private var isAmharic = false
    private var isAutocorrectSuppressed = false
    private var expectedCursorPos = 0
    // AUTOCORRECT STATE
    private var isAutocorrectEnabled = false
    private var isDeleteSuggestionMode = false
    private var currentBestPrediction: String? = null 
    private var lastAutocorrect: Pair<String, String>? = null 
    private var currentSuggestions: List<Prediction> = emptyList()
    private var symbolPageIndex = 0
    private var amharicBuffer = ""
    private var isLastSpaceAutomatic = false
    private var isToolbarForced = false

    // POPUP SYSTEM (Overlay View)
    private var popupOverlay: TextView? = null

    // MAPPINGS
    // SEPARATORS: Triggers for Autocorrect + Next Word Prediction
    // Added Amharic Punctuation: ። (Full Stop), ፣ (Comma), ፤ (Semicolon), ፥ (Colon), ፦ (Preface), ፧ (Question)
    private val separators = setOf(".", ",", "!", "?", ";", ":", "።", "፣", "፤", "፥", "፦", "፧")

    private val charMap = mapOf(
        R.id.key_q to "q", R.id.key_w to "w", R.id.key_e to "e", R.id.key_r to "r", R.id.key_t to "t",
        R.id.key_y to "y", R.id.key_u to "u", R.id.key_i to "i", R.id.key_o to "o", R.id.key_p to "p",
        R.id.key_a to "a", R.id.key_s to "s", R.id.key_d to "d", R.id.key_f to "f", R.id.key_g to "g",
        R.id.key_h to "h", R.id.key_j to "j", R.id.key_k to "k", R.id.key_l to "l",
        R.id.key_z to "z", R.id.key_x to "x", R.id.key_c to "c", R.id.key_v to "v", R.id.key_b to "b",
        R.id.key_n to "n", R.id.key_m to "m"
    )

    private val hintMap = mapOf(
        R.id.key_q to "1", R.id.key_w to "2", R.id.key_e to "3", R.id.key_r to "4", R.id.key_t to "5",
        R.id.key_y to "6", R.id.key_u to "7", R.id.key_i to "8", R.id.key_o to "9", R.id.key_p to "0",
        R.id.key_a to "@", R.id.key_s to "#", R.id.key_d to "$", R.id.key_f to "%", R.id.key_g to "&",
        R.id.key_z to "-", R.id.key_x to "'", R.id.key_c to "\"", R.id.key_v to ":", R.id.key_b to ";"
    )

    override fun onCreate() {
        super.onCreate()
        DebugLogger.log("SERVICE", "onCreate")
        // Initialize Prediction Engine Asynchronously
        predictor = TextPredictor(this)
        predictor?.loadDictionary()
    }

    override fun onDestroy() {
        super.onDestroy()
        predictor?.flush() // Force save on close
        serviceScope.cancel()
    }

    override fun onCreateInputView(): View {
        return try {
            log("Service: onCreateInputView started")
            loadMainKeyboard()
        } catch (e: Throwable) {
            e.printStackTrace()
            val scroll = ScrollView(this)
            val text = TextView(this)
            text.text = "CRITICAL INIT FAILURE:\n${e.stackTraceToString()}"
            text.setTextColor(0xFFFF0000.toInt())
            text.setPadding(20, 20, 20, 20)
            scroll.addView(text)
            scroll
        }
    }

    override fun onStartInputView(info: EditorInfo?, restarting: Boolean) {
        super.onStartInputView(info, restarting)
        val prefs = PreferenceManager.getDefaultSharedPreferences(this)
        isHapticEnabled = prefs.getBoolean("haptic_feedback", true)
        isSoundEnabled = prefs.getBoolean("sound_feedback", false)
        isNumberRowEnabled = prefs.getBoolean("show_number_row", false)
        isPopupEnabled = prefs.getBoolean("show_popups", true)
        isAutocorrectEnabled = prefs.getBoolean("enable_autocorrect", true)
        keyboardHeightPercent = prefs.getInt("kb_height", 150)

        // LOAD SAVED THEME
        isDarkTheme = prefs.getBoolean("is_dark_theme", true)

        log("Service: onStartInputView (Height: $keyboardHeightPercent%)")
        val view = loadMainKeyboard()
        setInputView(view)
        applyTheme(view) // Apply colors immediately
        updateCapsState()
        // PROACTIVE PREDICTION: Check context immediately on load
        updateSuggestions()
    }

    override fun onUpdateSelection(oldSelStart: Int, oldSelEnd: Int, newSelStart: Int, newSelEnd: Int, candidatesStart: Int, candidatesEnd: Int) {
        cursorPos = newSelEnd
        super.onUpdateSelection(oldSelStart, oldSelEnd, newSelStart, newSelEnd, candidatesStart, candidatesEnd)

        // CRITICAL: AMHARIC BUFFER RESET
        // If the cursor position is not where we expected it to be after a commit, 
        // the user likely moved it manually. Flush the buffer to avoid corrupting text.
        if (isAmharic && amharicBuffer.isNotEmpty() && newSelEnd != expectedCursorPos) {
            amharicBuffer = ""
        }

        updateCapsState()
    }

    private fun updateCapsState() {
        if (isCapsLocked) return // Don't override Lock

        val ic = currentInputConnection ?: return
        val info = currentInputEditorInfo ?: return

        // Ask Android System: "Based on the input type and cursor pos, should I be caps?"
        // 16384 = TextUtils.CAP_MODE_SENTENCES (We use magic number to avoid Android dependency issues in pure Kotlin files if context missing)
        val capsMode = ic.getCursorCapsMode(info.inputType)

        val shouldBeCaps = capsMode != 0
        if (isCaps != shouldBeCaps) {
            isCaps = shouldBeCaps
            updateCapsUI()
        }
    }

