    override fun onCreate() {
        super.onCreate()
        DebugLogger.log("SERVICE", "onCreate")
        // Initialize Prediction Engine Asynchronously
        predictor = TextPredictor(this)
        predictor?.loadDictionary()
    }

    override fun onDestroy() {
        super.onDestroy()
        predictor?.flush() // Force save on close
        serviceScope.cancel()
    }

    override fun onCreateInputView(): View {
        return try {
            log("Service: onCreateInputView started")
            loadMainKeyboard()
        } catch (e: Throwable) {
            e.printStackTrace()
            val scroll = ScrollView(this)
            val text = TextView(this)
            text.text = "CRITICAL INIT FAILURE:\n${e.stackTraceToString()}"
            text.setTextColor(0xFFFF0000.toInt())
            text.setPadding(20, 20, 20, 20)
            scroll.addView(text)
            scroll
        }
    }

    override fun onStartInputView(info: EditorInfo?, restarting: Boolean) {
        super.onStartInputView(info, restarting)
        val prefs = PreferenceManager.getDefaultSharedPreferences(this)
        isHapticEnabled = prefs.getBoolean("haptic_feedback", true)
        isSoundEnabled = prefs.getBoolean("sound_feedback", false)
        isNumberRowEnabled = prefs.getBoolean("show_number_row", false)
        isPopupEnabled = prefs.getBoolean("show_popups", true)
        isAutocorrectEnabled = prefs.getBoolean("enable_autocorrect", true)
        keyboardHeightPercent = prefs.getInt("kb_height", 150)

        // LOAD SAVED THEME
        isDarkTheme = prefs.getBoolean("is_dark_theme", true)

        log("Service: onStartInputView (Height: $keyboardHeightPercent%)")
        val view = loadMainKeyboard()
        setInputView(view)
        applyTheme(view) // Apply colors immediately
        updateCapsState()
        // PROACTIVE PREDICTION: Check context immediately on load
        updateSuggestions()
    }

    override fun onUpdateSelection(oldSelStart: Int, oldSelEnd: Int, newSelStart: Int, newSelEnd: Int, candidatesStart: Int, candidatesEnd: Int) {
        cursorPos = newSelEnd
        super.onUpdateSelection(oldSelStart, oldSelEnd, newSelStart, newSelEnd, candidatesStart, candidatesEnd)

        // CRITICAL: AMHARIC BUFFER RESET
        // If the cursor position is not where we expected it to be after a commit, 
        // the user likely moved it manually. Flush the buffer to avoid corrupting text.
        if (isAmharic && amharicBuffer.isNotEmpty() && newSelEnd != expectedCursorPos) {
            amharicBuffer = ""
        }

        updateCapsState()
    }

    private fun updateCapsState() {
        if (isCapsLocked) return // Don't override Lock

        val ic = currentInputConnection ?: return
        val info = currentInputEditorInfo ?: return

        // Ask Android System: "Based on the input type and cursor pos, should I be caps?"
        // 16384 = TextUtils.CAP_MODE_SENTENCES (We use magic number to avoid Android dependency issues in pure Kotlin files if context missing)
        val capsMode = ic.getCursorCapsMode(info.inputType)

        val shouldBeCaps = capsMode != 0
        if (isCaps != shouldBeCaps) {
            isCaps = shouldBeCaps
            updateCapsUI()
        }
    }

