    private fun loadMainKeyboard(): View {
        // OPTIMIZATION: Return cached view to avoid laggy inflation
        if (mainKeyboardCache != null) {
            currentLayoutView = mainKeyboardCache
            // FIX: Re-apply properties in case Settings changed (e.g. Height or Number Row)
            applyHeightScaling(mainKeyboardCache!!)
            val row = mainKeyboardCache!!.findViewById<View>(R.id.row_numbers)
            row.visibility = if (isNumberRowEnabled) View.VISIBLE else View.GONE
            return mainKeyboardCache!!
        }

        val view = layoutInflater.inflate(R.layout.layout_keyboard, null)
        mainKeyboardCache = view
        currentLayoutView = view

        applyHeightScaling(view)

        view.findViewById<View>(R.id.key_comma)?.let { bindKey(it, ",", null) }
        view.findViewById<View>(R.id.key_period)?.let { bindKey(it, ".", null) }

        // Number Row Logic
        val row = view.findViewById<View>(R.id.row_numbers)
        row.visibility = if (isNumberRowEnabled) View.VISIBLE else View.GONE
        if (isNumberRowEnabled) setupNumberRow(view)

        setupToolbar(view)
        setupKeys(view)

        // Switcher
        view.findViewById<TextView>(R.id.key_space)?.parent?.let { parent ->
             val switcher = (parent as ViewGroup).getChildAt(0)
             switcher.setOnClickListener {
                 setInputView(loadSymbolKeyboard())
             }
        }

        return view
    }

    private fun loadSymbolKeyboard(): View {
        val view = if (symbolKeyboardCache != null) {
            symbolKeyboardCache!!
        } else {
            val v = layoutInflater.inflate(R.layout.layout_symbols, null)
            symbolKeyboardCache = v
            setupSymbolKeys(v)
            v
        }

        currentLayoutView = view
        applyHeightScaling(view)
        // FIX: Ensure theme is applied to symbols every time it loads
        applyTheme(view)
        return view
    }

    private fun loadClipboardView(): View {
        val view = layoutInflater.inflate(R.layout.layout_clipboard, null)
        currentLayoutView = view

        view.minimumHeight = getKeyboardTotalHeight()

        // 1. Capture ALL current system clips
        val cm = getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager
        if (cm.hasPrimaryClip()) {
            val clip = cm.primaryClip
            if (clip != null) {
                // Loop through all items in the primary clip
                for (i in 0 until clip.itemCount) {
                    val text = clip.getItemAt(i).coerceToText(this).toString()
                    if (text.isNotBlank()) {
                        ClipHistoryRepo.addClip(this, text)
                    }
                }
            }
        }

        // 2. Render List
        val container = view.findViewById<LinearLayout>(R.id.clip_container)
        val history = ClipHistoryRepo.getHistory(this)

        if (history.isEmpty()) {
            val emptyMsg = TextView(this)
            emptyMsg.text = "No clips yet. Copy something!"
            emptyMsg.setTextColor(0xFF888888.toInt())
            emptyMsg.gravity = Gravity.CENTER
            emptyMsg.setPadding(30, 30, 30, 30)
            container.addView(emptyMsg)
        } else {
            history.forEach { clipContent ->
                val itemLayout = LinearLayout(this)
                itemLayout.orientation = LinearLayout.VERTICAL
                itemLayout.background = getDrawable(R.drawable.bg_key_normal)
                val params = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.WRAP_CONTENT)
                params.setMargins(0, 4, 0, 8)
                itemLayout.layoutParams = params
                itemLayout.setPadding(20, 20, 20, 20)

                val tv = TextView(this)
                tv.text = clipContent
                tv.textSize = 14f
                tv.setTextColor(0xFFFFFFFF.toInt())
                tv.maxLines = 3
                tv.ellipsize = android.text.TextUtils.TruncateAt.END
                tv.typeface = Typeface.SANS_SERIF

                itemLayout.addView(tv)
                itemLayout.setOnClickListener {
                    commit(clipContent)
                    setInputView(loadMainKeyboard())
                }
                container.addView(itemLayout)
            }
        }

        // Controls
        view.findViewById<Button>(R.id.btn_back_kb).setOnClickListener { setInputView(loadMainKeyboard()) }
        view.findViewById<Button>(R.id.btn_clear_clips).setOnClickListener {
            ClipHistoryRepo.clear(this)
            setInputView(loadClipboardView()) // Refresh
        }

        applyTheme(view)
        return view
    }

