    private fun updateSuggestions() {
        searchJob?.cancel()
        if (isDeleteSuggestionMode) return // Don't interrupt delete confirmation

        val ic = currentInputConnection ?: return
        val text = ic.getTextBeforeCursor(60, 0)?.toString() ?: ""

        // PARSE CONTEXT
        val parts = text.split(" ", "\n")
        val currentWordRaw = parts.lastOrNull() ?: ""
        val currentWord = currentWordRaw.trim { !it.isLetterOrDigit() }

        // CONTEXT EXTRACTION (Trigram Support)
        val previousRaw = if (parts.size >= 2) parts[parts.size - 2] else ""
        val previousWord = previousRaw.trim { !it.isLetterOrDigit() }

        val ppRaw = if (parts.size >= 3) parts[parts.size - 3] else ""
        val ppWord = ppRaw.trim { !it.isLetterOrDigit() }

        // UI STATE LOGIC: Toolbar vs Suggestions
        // 1. If currently typing a word -> SHOW SUGGESTIONS
        // 2. If just finished a sentence (Empty current + Dot/Exclam/Quest prev) -> SHOW TOOLBAR
        // 3. If empty field -> SHOW TOOLBAR
        // 4. If mid-sentence space (Empty current + No terminator) -> SHOW SUGGESTIONS (Bigrams)

        if (currentWord.isEmpty()) {
            val isSentenceEnd = previousRaw.endsWith(".") || previousRaw.endsWith("!") || previousRaw.endsWith("?")
            if (text.isBlank() || isSentenceEnd) {
                showSuggestionsUI(emptyList()) // Forces Toolbar
                return
            }
        }

        searchJob = serviceScope.launch {
            val suggestions = withContext(Dispatchers.Default) {
                // Pass full context (Trigram)
                predictor?.predict(currentWord, previousWord, ppWord, isAmharic) ?: emptyList()
            }
            if (isActive) {
                showSuggestionsUI(suggestions)
            }
        }
    }

    private fun showSuggestionsUI(preds: List<Prediction>) {
        // Capture the best prediction for Autocorrect logic
        currentBestPrediction = preds.firstOrNull()?.text
        currentSuggestions = preds

        val root = currentLayoutView ?: return
        val strip = root.findViewById<LinearLayout>(R.id.row_suggestions) ?: return
        val toolbarScroll = root.findViewById<View>(R.id.toolbar_scroll)
        val toggleBtn = root.findViewById<ImageView>(R.id.btn_quick_menu)

        // UPDATE TOGGLE ICON: Chevron Left if Open, Right if Closed
        toggleBtn?.rotation = if (isToolbarForced) 180f else 0f

        if (isToolbarForced) {
            // FORCED TOOLBAR MODE: Show Toolbar, Hide Suggestions
            strip.visibility = View.GONE
            toolbarScroll?.visibility = View.VISIBLE
            return
        }

        // STANDARD MODE
        if (preds.isEmpty()) {
            strip.visibility = View.GONE
            toolbarScroll?.visibility = View.VISIBLE
            return
        }

        strip.visibility = View.VISIBLE
        toolbarScroll?.visibility = View.GONE



        val textViews = listOf(
            root.findViewById<TextView>(R.id.suggestion_1),
            root.findViewById<TextView>(R.id.suggestion_2),
            root.findViewById<TextView>(R.id.suggestion_3)
        )

        for (i in 0 until 3) {
            if (i < preds.size) {
                val item = preds[i]
                textViews[i].text = item.text

                // STYLE: Highlight Auto-Correct Candidates
                if (isAutocorrectEnabled && i == 0 && item.shouldAutoCorrect) {
                     textViews[i].typeface = Typeface.DEFAULT_BOLD
                     textViews[i].setTextColor(0xFF3D6B99.toInt())
                } else {
                     textViews[i].typeface = Typeface.DEFAULT
                     textViews[i].setTextColor(if (isDarkTheme) 0xFFFFFFFF.toInt() else 0xFF000000.toInt())
                }

                // CLICK: Pick
                textViews[i].setOnClickListener {
                    pickSuggestion(item.text)
                }

                // LONG CLICK: Delete Mode
                textViews[i].setOnLongClickListener {
                    showDeleteConfirmation(item.text)
                    true
                }
            } else {
                textViews[i].text = ""
                textViews[i].setOnClickListener(null)
                textViews[i].setOnLongClickListener(null)
            }
        }
    }

    // DELETE UI LOGIC
    private fun showDeleteConfirmation(word: String) {
        val root = currentLayoutView ?: return
        isDeleteSuggestionMode = true // Lock UI

        val textViews = listOf<TextView>(
            root.findViewById(R.id.suggestion_1),
            root.findViewById(R.id.suggestion_2),
            root.findViewById(R.id.suggestion_3)
        )

        // SWAP UI to Delete Mode
        textViews[0].text = "DELETE?"
        textViews[0].setTextColor(0xFFFF0000.toInt())
        textViews[0].typeface = Typeface.DEFAULT_BOLD
        textViews[0].setOnClickListener {
            // CONFIRM DELETE
            serviceScope.launch(Dispatchers.Default) { predictor?.removeWord(word) }
            isDeleteSuggestionMode = false
            updateSuggestions() 
        }
        textViews[0].setOnLongClickListener(null)

        textViews[1].text = word
        textViews[1].setTextColor(if (isDarkTheme) 0xFFFFFFFF.toInt() else 0xFF000000.toInt())
        textViews[1].setOnClickListener(null)
        textViews[1].setOnLongClickListener(null)

        textViews[2].text = "CANCEL"
        textViews[2].setTextColor(if (isDarkTheme) 0xFFFFFFFF.toInt() else 0xFF000000.toInt())
        textViews[2].setOnClickListener {
             isDeleteSuggestionMode = false
             updateSuggestions() 
        }
        textViews[2].setOnLongClickListener(null)
    }

    private fun pickSuggestion(suggestion: String) {
        val ic = currentInputConnection ?: return
        val text = ic.getTextBeforeCursor(100, 0)?.toString() ?: ""

        // 1. Robust Tokenizer: Find start of current word
        // Scan back until we find a separator or start of string
        var i = text.length - 1
        while (i >= 0) {
            val c = text[i]
            // Allow apostrophe inside words (e.g. "don't") but stop at space/punct
            if (!c.isLetterOrDigit() && c != '\'') {
                break
            }
            i--
        }
        val start = i + 1
        val wordToReplace = text.substring(start)

        // NOTE: removed 'wordToReplace.isEmpty()' check to allow Next Word Prediction insertion

        // 2. Commit Replacement
        val commitText = suggestion + " "

        ic.beginBatchEdit()
        ic.finishComposingText() // Ensure clean state
        // If wordToReplace is empty, this deletes nothing (safe)
        ic.deleteSurroundingText(wordToReplace.length, 0)
        ic.commitText(commitText, 1)
        ic.endBatchEdit()

        // 3. State & Learning
        expectedCursorPos = cursorPos - wordToReplace.length + commitText.length
        lastAutocorrect = null // Manual pick invalidates undo
        isAutocorrectSuppressed = false
        isLastSpaceAutomatic = true

        DiscoveryLogger.log(this, "SUGGESTION_PICK", mapOf("typed" to wordToReplace, "picked" to suggestion, "lang" to if(isAmharic) "am" else "en"))
        serviceScope.launch(Dispatchers.Default) {
             // EXPLICIT LEARNING (User clicked the strip)
             predictor?.learnWord(suggestion, null, null, isExplicit = true)
             // Only learn correction if we actually replaced something substantive
             if (wordToReplace.isNotEmpty() && wordToReplace != suggestion) {
                 predictor?.learnCorrection(wordToReplace, suggestion)
             }
        }

        updateSuggestions()
    }

    // ========================================================
    // DEBUG
    // ========================================================

    private fun log(msg: String) {
        val time = SimpleDateFormat("HH:mm:ss").format(Date())
        debugLog.append("[$time] $msg\n")
    }

    // ========================================================
    // THEME ENGINE
    // ========================================================

    private fun applyTheme(root: View) {
        // COLOR PALETTE
        val bgColor = if (isDarkTheme) 0xFF141414.toInt() else 0xFFECECEC.toInt()
        val charKeyColor = if (isDarkTheme) 0xFF2D2F31.toInt() else 0xFFFFFFFF.toInt()
        val textColor = if (isDarkTheme) 0xFFFFFFFF.toInt() else 0xFF000000.toInt()
        val actionColor = 0xFF3D6B99.toInt() 

        // FUNCTIONAL KEYS (Shift, Del, 123) - Slightly distinct from Chars
        val funcKeyColor = if (isDarkTheme) 0xFF3C4043.toInt() else 0xFFDCDCDC.toInt()

        // 1. Set Main Backgrounds
        root.setBackgroundColor(bgColor)
        root.findViewById<View>(R.id.keyboard_content)?.setBackgroundColor(bgColor)
        // FIX: toolbar ID was removed, now using toolbar_scroll or the container
        root.findViewById<View>(R.id.toolbar_scroll)?.setBackgroundColor(bgColor)
        root.findViewById<View>(R.id.toolbar)?.setBackgroundColor(bgColor)
        root.findViewById<View>(R.id.row_suggestions)?.setBackgroundColor(bgColor)
        root.findViewById<View>(R.id.clip_container)?.setBackgroundColor(bgColor)

        // 2. Recursive Color Applicator
        fun colorize(v: View) {
            if (v is ViewGroup) {
                for (i in 0 until v.childCount) {
                    colorize(v.getChildAt(i))
                }

                // Apply Tint to Key-like backgrounds
                val bg = v.background
                if (bg != null && v.id != R.id.keyboard_content && v.id != R.id.toolbar && v.id != R.id.row_numbers && v.id != R.id.clip_container) {
                     val color = when (v.id) {
                         R.id.key_enter, R.id.key_enter_sym, 
                         R.id.btn_enable, R.id.btn_select, R.id.btn_clear_clips -> actionColor

                         R.id.key_shift, R.id.key_del, R.id.key_del_sym, 
                         R.id.key_mode_switch, R.id.key_sym_switch, R.id.key_back_abc,
                         R.id.btn_cut, R.id.btn_copy, R.id.btn_paste, R.id.btn_select_all -> funcKeyColor

                         else -> charKeyColor
                     }
                     v.backgroundTintList = android.content.res.ColorStateList.valueOf(color)
                }
            }

            if (v is TextView) {
                // Don't colorize the suggestions strip text or toolbar icons roughly
                if (v.id != R.id.tool_settings && v.id != R.id.suggestion_1 && v.id != R.id.suggestion_2 && v.id != R.id.suggestion_3) {
                    v.setTextColor(textColor)
                }
                // Suggestions text needs to be readable too
                if (v.id == R.id.suggestion_1 || v.id == R.id.suggestion_2 || v.id == R.id.suggestion_3) {
                    v.setTextColor(textColor)
                }
            }

            if (v is ImageView) {
                // Tint Toolbar Icons
                v.setColorFilter(if (isDarkTheme) 0xFF9AA0A6.toInt() else 0xFF5F6368.toInt())
            }
        }

        colorize(root)
    }

    private fun showDebugLog(root: View) {
        val scroll = ScrollView(this)
        scroll.background = android.graphics.drawable.ColorDrawable(0xFF000000.toInt())
        val text = TextView(this)
        text.text = debugLog.toString()
        text.setTextColor(0xFF00FF00.toInt())
        text.typeface = android.graphics.Typeface.MONOSPACE
        text.setPadding(20, 20, 20, 20)
        scroll.addView(text)

        val frame = FrameLayout(this)
        frame.addView(scroll)

        val btnLayout = LinearLayout(this)
        btnLayout.orientation = LinearLayout.HORIZONTAL
        btnLayout.gravity = Gravity.CENTER

        val close = Button(this)
        close.text = "CLOSE LOG"
        close.setOnClickListener { setInputView(loadMainKeyboard()) }

        val settings = Button(this)
        settings.text = "OPEN SETTINGS"
        settings.setOnClickListener {
             startActivity(Intent(this, SettingsActivity::class.java).addFlags(Intent.FLAG_ACTIVITY_NEW_TASK))
        }

        btnLayout.addView(close)
        btnLayout.addView(settings)

        // UI STABILITY: Enforce Height
        frame.minimumHeight = getKeyboardTotalHeight()
        frame.addView(btnLayout, FrameLayout.LayoutParams(ViewGroup.LayoutParams.WRAP_CONTENT, ViewGroup.LayoutParams.WRAP_CONTENT, Gravity.BOTTOM or Gravity.CENTER_HORIZONTAL))

        setInputView(frame)
    }
}

