package com.gboard.clone

import android.content.ClipboardManager
import android.content.Context
import android.content.Intent
import android.inputmethodservice.InputMethodService
import android.media.AudioManager
import android.view.Gravity
import android.view.HapticFeedbackConstants
import android.view.KeyEvent
import android.view.MotionEvent
import android.view.View
import android.view.ViewGroup
import android.view.inputmethod.EditorInfo
import android.widget.Button
import android.widget.FrameLayout
import android.widget.ImageView
import android.widget.LinearLayout
import android.widget.PopupWindow
import android.widget.ScrollView
import android.widget.TextView
import androidx.preference.PreferenceManager
import java.text.SimpleDateFormat
import java.util.Date
import android.graphics.Typeface
import android.graphics.PorterDuff
import android.graphics.PorterDuffColorFilter
import android.graphics.Color
import androidx.core.content.res.ResourcesCompat
import kotlinx.coroutines.*

class KeyboardService : InputMethodService() {

    // STATE
    private var currentLayoutView: View? = null
    private var isCaps = false
    private var isCapsLocked = false
    private var isHapticEnabled = true
    private var isSoundEnabled = false
    private var isNumberRowEnabled = false
    private var isPopupEnabled = true
    private var isOneHanded = false
    private var isDarkTheme = true
    private var cursorPos = 0
    private var keyboardHeightPercent = 100
    private var lastTouchX = 0f
    private var lastSpaceTime = 0L

    // PREDICTION
    private var predictor: TextPredictor? = null

    // DEBUG
    // Logging StringBuilder for debugging purposes
    private val debugLog = StringBuilder()

    // OPTIMIZATION: Coroutine Scope & View Caching
    private val serviceScope = CoroutineScope(Dispatchers.Main + Job())
    private var mainKeyboardCache: View? = null
    private var symbolKeyboardCache: View? = null
    private var searchJob: Job? = null
    // AMHARIC STATE
    private var isAmharic = false
    private var isAutocorrectSuppressed = false
    private var expectedCursorPos = 0
    // AUTOCORRECT STATE
    private var isAutocorrectEnabled = false
    private var isDeleteSuggestionMode = false
    private var currentBestPrediction: String? = null 
    private var lastAutocorrect: Pair<String, String>? = null 
    private var currentSuggestions: List<Prediction> = emptyList()
    private var symbolPageIndex = 0
    private var amharicBuffer = ""
    private var isLastSpaceAutomatic = false
    private var isToolbarForced = false

    // POPUP SYSTEM (Overlay View)
    private var popupOverlay: TextView? = null

    // MAPPINGS
    // SEPARATORS: Triggers for Autocorrect + Next Word Prediction
    // Added Amharic Punctuation: ። (Full Stop), ፣ (Comma), ፤ (Semicolon), ፥ (Colon), ፦ (Preface), ፧ (Question)
    private val separators = setOf(".", ",", "!", "?", ";", ":", "።", "፣", "፤", "፥", "፦", "፧")

    private val charMap = mapOf(
        R.id.key_q to "q", R.id.key_w to "w", R.id.key_e to "e", R.id.key_r to "r", R.id.key_t to "t",
        R.id.key_y to "y", R.id.key_u to "u", R.id.key_i to "i", R.id.key_o to "o", R.id.key_p to "p",
        R.id.key_a to "a", R.id.key_s to "s", R.id.key_d to "d", R.id.key_f to "f", R.id.key_g to "g",
        R.id.key_h to "h", R.id.key_j to "j", R.id.key_k to "k", R.id.key_l to "l",
        R.id.key_z to "z", R.id.key_x to "x", R.id.key_c to "c", R.id.key_v to "v", R.id.key_b to "b",
        R.id.key_n to "n", R.id.key_m to "m"
    )

    private val hintMap = mapOf(
        R.id.key_q to "1", R.id.key_w to "2", R.id.key_e to "3", R.id.key_r to "4", R.id.key_t to "5",
        R.id.key_y to "6", R.id.key_u to "7", R.id.key_i to "8", R.id.key_o to "9", R.id.key_p to "0",
        R.id.key_a to "@", R.id.key_s to "#", R.id.key_d to "$", R.id.key_f to "%", R.id.key_g to "&",
        R.id.key_z to "-", R.id.key_x to "'", R.id.key_c to "\"", R.id.key_v to ":", R.id.key_b to ";"
    )

    override fun onCreate() {
        super.onCreate()
        DebugLogger.log("SERVICE", "onCreate")
        // Initialize Prediction Engine Asynchronously
        predictor = TextPredictor(this)
        predictor?.loadDictionary()
    }

    override fun onDestroy() {
        super.onDestroy()
        predictor?.flush() // Force save on close
        serviceScope.cancel()
    }

    override fun onCreateInputView(): View {
        return try {
            log("Service: onCreateInputView started")
            loadMainKeyboard()
        } catch (e: Throwable) {
            e.printStackTrace()
            val scroll = ScrollView(this)
            val text = TextView(this)
            text.text = "CRITICAL INIT FAILURE:\n${e.stackTraceToString()}"
            text.setTextColor(0xFFFF0000.toInt())
            text.setPadding(20, 20, 20, 20)
            scroll.addView(text)
            scroll
        }
    }

    override fun onStartInputView(info: EditorInfo?, restarting: Boolean) {
        super.onStartInputView(info, restarting)
        val prefs = PreferenceManager.getDefaultSharedPreferences(this)
        isHapticEnabled = prefs.getBoolean("haptic_feedback", true)
        isSoundEnabled = prefs.getBoolean("sound_feedback", false)
        isNumberRowEnabled = prefs.getBoolean("show_number_row", false)
        isPopupEnabled = prefs.getBoolean("show_popups", true)
        isAutocorrectEnabled = prefs.getBoolean("enable_autocorrect", true)
        keyboardHeightPercent = prefs.getInt("kb_height", 150)

        // LOAD SAVED THEME
        isDarkTheme = prefs.getBoolean("is_dark_theme", true)

        log("Service: onStartInputView (Height: $keyboardHeightPercent%)")
        val view = loadMainKeyboard()
        setInputView(view)
        applyTheme(view) // Apply colors immediately
        updateCapsState()
        // PROACTIVE PREDICTION: Check context immediately on load
        updateSuggestions()
    }

    override fun onUpdateSelection(oldSelStart: Int, oldSelEnd: Int, newSelStart: Int, newSelEnd: Int, candidatesStart: Int, candidatesEnd: Int) {
        cursorPos = newSelEnd
        super.onUpdateSelection(oldSelStart, oldSelEnd, newSelStart, newSelEnd, candidatesStart, candidatesEnd)

        // CRITICAL: AMHARIC BUFFER RESET
        // If the cursor position is not where we expected it to be after a commit, 
        // the user likely moved it manually. Flush the buffer to avoid corrupting text.
        if (isAmharic && amharicBuffer.isNotEmpty() && newSelEnd != expectedCursorPos) {
            amharicBuffer = ""
        }

        updateCapsState()
    }

    private fun updateCapsState() {
        if (isCapsLocked) return // Don't override Lock

        val ic = currentInputConnection ?: return
        val info = currentInputEditorInfo ?: return

        // Ask Android System: "Based on the input type and cursor pos, should I be caps?"
        // 16384 = TextUtils.CAP_MODE_SENTENCES (We use magic number to avoid Android dependency issues in pure Kotlin files if context missing)
        val capsMode = ic.getCursorCapsMode(info.inputType)

        val shouldBeCaps = capsMode != 0
        if (isCaps != shouldBeCaps) {
            isCaps = shouldBeCaps
            updateCapsUI()
        }
    }

    // ========================================================
    // UI LOADERS
    // ========================================================

    private fun loadMainKeyboard(): View {
        // OPTIMIZATION: Return cached view to avoid laggy inflation
        if (mainKeyboardCache != null) {
            currentLayoutView = mainKeyboardCache
            // FIX: Re-apply properties in case Settings changed (e.g. Height or Number Row)
            applyHeightScaling(mainKeyboardCache!!)
            val row = mainKeyboardCache!!.findViewById<View>(R.id.row_numbers)
            row.visibility = if (isNumberRowEnabled) View.VISIBLE else View.GONE
            return mainKeyboardCache!!
        }

        val view = layoutInflater.inflate(R.layout.layout_keyboard, null)
        mainKeyboardCache = view
        currentLayoutView = view

        applyHeightScaling(view)

        view.findViewById<View>(R.id.key_comma)?.let { bindKey(it, ",", null) }
        view.findViewById<View>(R.id.key_period)?.let { bindKey(it, ".", null) }

        // Number Row Logic
        val row = view.findViewById<View>(R.id.row_numbers)
        row.visibility = if (isNumberRowEnabled) View.VISIBLE else View.GONE
        if (isNumberRowEnabled) setupNumberRow(view)

        setupToolbar(view)
        setupKeys(view)

        // Switcher
        view.findViewById<TextView>(R.id.key_space)?.parent?.let { parent ->
             val switcher = (parent as ViewGroup).getChildAt(0)
             switcher.setOnClickListener {
                 setInputView(loadSymbolKeyboard())
             }
        }

        return view
    }

    private fun loadSymbolKeyboard(): View {
        val view = if (symbolKeyboardCache != null) {
            symbolKeyboardCache!!
        } else {
            val v = layoutInflater.inflate(R.layout.layout_symbols, null)
            symbolKeyboardCache = v
            setupSymbolKeys(v)
            v
        }

        currentLayoutView = view
        applyHeightScaling(view)
        // FIX: Ensure theme is applied to symbols every time it loads
        applyTheme(view)
        return view
    }

    private fun loadClipboardView(): View {
        val view = layoutInflater.inflate(R.layout.layout_clipboard, null)
        currentLayoutView = view

        view.minimumHeight = getKeyboardTotalHeight()

        // 1. Capture ALL current system clips
        val cm = getSystemService(Context.CLIPBOARD_SERVICE) as ClipboardManager
        if (cm.hasPrimaryClip()) {
            val clip = cm.primaryClip
            if (clip != null) {
                // Loop through all items in the primary clip
                for (i in 0 until clip.itemCount) {
                    val text = clip.getItemAt(i).coerceToText(this).toString()
                    if (text.isNotBlank()) {
                        ClipHistoryRepo.addClip(this, text)
                    }
                }
            }
        }

        // 2. Render List
        val container = view.findViewById<LinearLayout>(R.id.clip_container)
        val history = ClipHistoryRepo.getHistory(this)

        if (history.isEmpty()) {
            val emptyMsg = TextView(this)
            emptyMsg.text = "No clips yet. Copy something!"
            emptyMsg.setTextColor(0xFF888888.toInt())
            emptyMsg.gravity = Gravity.CENTER
            emptyMsg.setPadding(30, 30, 30, 30)
            container.addView(emptyMsg)
        } else {
            history.forEach { clipContent ->
                val itemLayout = LinearLayout(this)
                itemLayout.orientation = LinearLayout.VERTICAL
                itemLayout.background = getDrawable(R.drawable.bg_key_normal)
                val params = LinearLayout.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.WRAP_CONTENT)
                params.setMargins(0, 4, 0, 8)
                itemLayout.layoutParams = params
                itemLayout.setPadding(20, 20, 20, 20)

                val tv = TextView(this)
                tv.text = clipContent
                tv.textSize = 14f
                tv.setTextColor(0xFFFFFFFF.toInt())
                tv.maxLines = 3
                tv.ellipsize = android.text.TextUtils.TruncateAt.END
                tv.typeface = Typeface.SANS_SERIF

                itemLayout.addView(tv)
                itemLayout.setOnClickListener {
                    commit(clipContent)
                    setInputView(loadMainKeyboard())
                }
                container.addView(itemLayout)
            }
        }

        // Controls
        view.findViewById<Button>(R.id.btn_back_kb).setOnClickListener { setInputView(loadMainKeyboard()) }
        view.findViewById<Button>(R.id.btn_clear_clips).setOnClickListener {
            ClipHistoryRepo.clear(this)
            setInputView(loadClipboardView()) // Refresh
        }

        applyTheme(view)
        return view
    }

    private fun loadDebugView(): View {
        val scroll = ScrollView(this)
        scroll.layoutParams = ViewGroup.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, ViewGroup.LayoutParams.MATCH_PARENT)
        scroll.background = android.graphics.drawable.ColorDrawable(if(isDarkTheme) 0xFF141414.toInt() else 0xFFECECEC.toInt())

        val content = LinearLayout(this)
        content.orientation = LinearLayout.VERTICAL
        content.paddingTop = 16
        content.paddingBottom = 16
        content.setPadding(20, 20, 20, 20)

        val title = TextView(this)
        title.text = "DEBUG CONSOLE"
        title.typeface = Typeface.DEFAULT_BOLD
        title.textSize = 16f
        title.setTextColor(if(isDarkTheme) 0xFFFFFFFF.toInt() else 0xFF000000.toInt())
        content.addView(title)

        val controls = LinearLayout(this)
        controls.orientation = LinearLayout.HORIZONTAL

        val btnClear = Button(this)
        btnClear.text = "CLEAR"
        btnClear.setOnClickListener { 
            DebugLogger.clear()
            setInputView(loadDebugView()) // Refresh
        }

        val btnClose = Button(this)
        btnClose.text = "CLOSE"
        btnClose.setOnClickListener { setInputView(loadMainKeyboard()) }

        controls.addView(btnClear)
        controls.addView(btnClose)
        content.addView(controls)

        val logText = TextView(this)
        logText.text = DebugLogger.getLogs()
        logText.typeface = Typeface.MONOSPACE
        logText.textSize = 10f
        logText.setTextColor(0xFF00FF00.toInt())
        content.addView(logText)

        scroll.addView(content)
        // Set height
        val params = ViewGroup.LayoutParams(ViewGroup.LayoutParams.MATCH_PARENT, getKeyboardTotalHeight())
        scroll.layoutParams = params
        scroll.minimumHeight = getKeyboardTotalHeight()

        return scroll
    }

    private fun loadTextEditor(): View {
        val view = layoutInflater.inflate(R.layout.layout_text_editor, null)
        currentLayoutView = view
        view.minimumHeight = getKeyboardTotalHeight()

        val ic = currentInputConnection ?: return view

        // OPTIMIZATION: Use auto-repeat for navigation keys
        bindRepeatableKey(view.findViewById(R.id.btn_up)) { ic.sendKeyEvent(KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_DPAD_UP)) }
        bindRepeatableKey(view.findViewById(R.id.btn_down)) { ic.sendKeyEvent(KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_DPAD_DOWN)) }
        bindRepeatableKey(view.findViewById(R.id.btn_left)) { ic.sendKeyEvent(KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_DPAD_LEFT)) }
        bindRepeatableKey(view.findViewById(R.id.btn_right)) { ic.sendKeyEvent(KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_DPAD_RIGHT)) }

        // Standard click for non-repeating actions
        view.findViewById<View>(R.id.btn_home).setOnClickListener { ic.sendKeyEvent(KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_MOVE_HOME)) }
        view.findViewById<View>(R.id.btn_end).setOnClickListener { ic.sendKeyEvent(KeyEvent(KeyEvent.ACTION_DOWN, KeyEvent.KEYCODE_MOVE_END)) }

        view.findViewById<View>(R.id.btn_select_all).setOnClickListener { ic.performContextMenuAction(android.R.id.selectAll) }
        view.findViewById<View>(R.id.btn_cut).setOnClickListener { ic.performContextMenuAction(android.R.id.cut) }
        view.findViewById<View>(R.id.btn_copy).setOnClickListener { ic.performContextMenuAction(android.R.id.copy) }
        view.findViewById<View>(R.id.btn_paste).setOnClickListener { ic.performContextMenuAction(android.R.id.paste) }
        view.findViewById<View>(R.id.btn_close_editor).setOnClickListener { setInputView(loadMainKeyboard()) }

        applyTheme(view)
        return view
    }

    // ========================================================
    // SIZING & SCALING
    // ========================================================

    private fun getKeyboardTotalHeight(): Int {
        val density = resources.displayMetrics.density
        val rowHeight = (50f * (keyboardHeightPercent / 100f) * density).toInt()
        val numRows = if (isNumberRowEnabled) 5 else 4
        val toolbarHeight = (40f * density).toInt()
        return (rowHeight * numRows) + toolbarHeight
    }

    private fun applyHeightScaling(view: View) {
        // HELPER: Aggressively remove margins from ANY key to fix touch dead zones
        fun removeMargins(row: ViewGroup) {
            for (i in 0 until row.childCount) {
                val child = row.getChildAt(i)
                // Target both Layouts (Letter Keys) and TextViews (Shift/Delete/Enter)
                if (child.layoutParams is LinearLayout.LayoutParams) {
                     val lp = child.layoutParams as LinearLayout.LayoutParams
                     // Eliminate gap. The background drawable's inset handles the visual spacing.
                     lp.setMargins(0, 0, 0, 0)
                     child.layoutParams = lp
                }
            }
        }

        // RECURSIVE FIX
        if (view is FrameLayout) {
            val content = view.findViewById<ViewGroup>(R.id.keyboard_content)
            if (content != null) {
                applyHeightScaling(content)
                return
            }
        }

        val baseHeightDp = 50f
        val scale = keyboardHeightPercent / 100f
        val scaledHeightPx = (baseHeightDp * scale * resources.displayMetrics.density).toInt()

        if (view is ViewGroup) {
            for (i in 0 until view.childCount) {
                val child = view.getChildAt(i)
                // Apply to all rows including Number row, but exclude Toolbar/Suggestions
                // NOTE: We check for toolbar_scroll (parent of toolbar) and row_suggestions
                if (child is LinearLayout && child.id != R.id.keyboard_content && child.id != R.id.row_suggestions) {
                    // Explicit check to skip the top menu row (which contains toolbar)
                    // The top row is the first child of keyboard_content
                    if (view.id == R.id.keyboard_content && i == 0) continue

                    // Safely modify layout params
                    child.layoutParams?.let { lp ->
                        lp.height = scaledHeightPx
                        child.layoutParams = lp
                    }

                    // Apply Dead Zone Fix to this row
                    removeMargins(child)
                }
            }
        }
    }

    // ========================================================
    // KEY SETUP & LOGIC
    // ========================================================

    private fun setupKeys(root: View) {
        // LOAD CUSTOM FONT
        val customFont = try {
            ResourcesCompat.getFont(this, R.font.roboto_bold)
        } catch (e: Exception) {
            Typeface.DEFAULT_BOLD
        }

        // INIT POPUP OVERLAY
        popupOverlay = root.findViewById(R.id.overlay_popup)
        popupOverlay?.typeface = customFont

        charMap.forEach { (id, char) ->
            val keyContainer = root.findViewById<ViewGroup>(id)
            val keyLabel = keyContainer.findViewById<TextView>(R.id.key_label)
            val keyHint = keyContainer.findViewById<TextView>(R.id.key_hint_label)

            // APPLY CUSTOM FONT
            keyLabel.typeface = customFont
            keyLabel.text = char

            val hint = hintMap[id]
            if (hint != null) {
                keyHint.text = hint
                keyHint.visibility = View.VISIBLE
            } else {
                keyHint.visibility = View.GONE
            }

            bindKey(keyContainer, char, hint)
        }

        // SPACEBAR LOGIC
        val space = root.findViewById<View>(R.id.key_space)

        // CLICK HANDLER (Tap)
        // CLICK HANDLER (Tap)
        space.setOnClickListener {
            val ic = currentInputConnection
            if (ic == null) return@setOnClickListener

            // 1. GET TYPED WORD (Before any changes)
            val rawTypedWord = ic.getTextBeforeCursor(50, 0)?.toString()?.substringAfterLast(" ")?.substringAfterLast("\n") ?: ""

            // 2. AUTOCORRECT LOGIC
            var processedAutoCorrect = false

            // SPECIAL RULE: FORCE 'I' CAPITALIZATION
            if (!isAmharic && rawTypedWord == "i") {
                 ic.beginBatchEdit()
                 ic.deleteSurroundingText(1, 0)
                 ic.commitText("I ", 1)
                 ic.endBatchEdit()
                 processedAutoCorrect = true
            }

            // 1.5 CHECK CONTEXT: If punctuation is immediately before, DO NOT autocorrect.
            // Scenario: User typed "word." (already AC'd). Now types Space.
            val charBefore = ic.getTextBeforeCursor(1, 0)?.toString() ?: ""
            val isSeparatorBefore = separators.contains(charBefore)

            // CHECK SUPPRESS FLAG & SEPARATORS & CONFIDENCE
            // We only autocorrect if the engine marked the prediction as "shouldAutoCorrect" (Confident)
            if (!processedAutoCorrect && !isSeparatorBefore && isAutocorrectEnabled && !isAmharic && currentBestPrediction != null && !isAutocorrectSuppressed) {
                val bestPred = currentSuggestions.firstOrNull()
                val replacement = bestPred?.text ?: ""
                val isConfident = bestPred?.shouldAutoCorrect == true

                // VALID WORD PROTECTION:
                // 1. Check if it's in the top suggestions (Fastest)
                // 2. Check the entire dictionary (Deep Check)
                // This prevents correcting valid words that just happen to be low rank (e.g. "were" vs "we're")
                val isRawWordValid = currentSuggestions.any { it.text.equals(rawTypedWord, ignoreCase = true) } 
                        || predictor?.isValidWord(rawTypedWord) == true

                // EXCEPTION: Always correct to "I" even if the single letter input exists in dictionary
                val isException = replacement == "I"

                // Only Apply if CONFIDENT and Raw word is invalid (unless exception)
                if (isConfident && rawTypedWord.isNotEmpty() && rawTypedWord != replacement && (!isRawWordValid || isException)) {
                    DiscoveryLogger.log(this, "AUTOCORRECT", mapOf("typed" to rawTypedWord, "fixed" to replacement, "lang" to "en"))
                    ic.beginBatchEdit()
                    ic.deleteSurroundingText(rawTypedWord.length, 0)
                    ic.commitText(replacement + " ", 1)
                    ic.endBatchEdit()

                    lastAutocorrect = Pair(rawTypedWord, replacement)
                    processedAutoCorrect = true
                    isLastSpaceAutomatic = true

                    // LEARN: Boost the word we just corrected to
                    serviceScope.launch(Dispatchers.Default) { 
                        // Auto-correct is semi-explicit, but we treat it as explicit because the engine provided it
                        predictor?.learnWord(replacement, null, null, isExplicit = true) 
                    }
                }
            }

            if (!processedAutoCorrect) {
                // LEARN: The user typed a word and hit space. Learn N-Grams.
                // UNBLOCKED: Amharic learning enabled.
                if (rawTypedWord.isNotEmpty()) {
                     // Extract Context for Learning
                     val fullText = ic.getTextBeforeCursor(100, 0)?.toString() ?: ""
                     val tokens = fullText.split(" ").filter { it.isNotBlank() }
                     // Tokens roughly: [..., prevPrev, prev, CURRENT]
                     val idx = tokens.size - 1
                     val prev = if (idx >= 1) tokens[idx - 1].trim { !it.isLetterOrDigit() } else null
                     val pp = if (idx >= 2) tokens[idx - 2].trim { !it.isLetterOrDigit() } else null

                     // IMPLICIT LEARNING (Spacebar)
                     // We pass false, so it requires 5 repetitions to be learned
                     serviceScope.launch(Dispatchers.Default) { predictor?.learnWord(rawTypedWord, prev, pp, isExplicit = false) }
                }

                val now = System.currentTimeMillis()
                if (now - lastSpaceTime < 300) {
                    ic.deleteSurroundingText(1, 0)
                    commit(". ")
                    lastSpaceTime = 0
                } else {
                    commit(" ")
                    lastSpaceTime = now
                }
            }
            updateSuggestions()
        }

        // SWIPE HANDLER (Cursor Move)
        space.setOnTouchListener(object : View.OnTouchListener {
            var startX = 0f
            var lastX = 0f
            var accumulatedDiff = 0f
            var isCursorMode = false

            // DENSITY SCALING
            // Threshold to start: 10dp
            // Sensitivity: 12dp per character (Lower = Faster, Higher = Slower/Precise)
            val density by lazy { resources.displayMetrics.density }
            val triggerThreshold by lazy { 10f * density }
            val stepThreshold by lazy { 12f * density }

            override fun onTouch(v: View, event: MotionEvent): Boolean {
                val ic = currentInputConnection ?: return false
                when (event.action) {
                    MotionEvent.ACTION_DOWN -> {
                        startX = event.x
                        lastX = event.x
                        accumulatedDiff = 0f
                        isCursorMode = false
                        v.isPressed = true
                        return true
                    }
                    MotionEvent.ACTION_MOVE -> {
                        // 1. Detect Mode Switch (Distance based, not Speed based)
                        if (!isCursorMode) {
                            if (Math.abs(event.x - startX) > triggerThreshold) {
                                isCursorMode = true
                                // Reset accumulation so the cursor doesn't jump immediately
                                accumulatedDiff = 0f 
                                if (isHapticEnabled) v.performHapticFeedback(HapticFeedbackConstants.KEYBOARD_TAP)
                            }
                        }

                        // 2. Handle Movement
                        if (isCursorMode) {
                            val diff = event.x - lastX
                            accumulatedDiff += diff

                            // Calculate steps based on Density-Aware threshold
                            // We use a float division then cast to get smoother handling
                            if (Math.abs(accumulatedDiff) >= stepThreshold) {
                                val steps = (accumulatedDiff / stepThreshold).toInt()
                                if (steps != 0) {
                                    val newPos = (cursorPos + steps).coerceAtLeast(0)
                                    ic.setSelection(newPos, newPos)

                                    // Consume the distance used
                                    accumulatedDiff -= (steps * stepThreshold)
                                }
                            }
                        }
                        lastX = event.x
                        return true
                    }
                    MotionEvent.ACTION_UP, MotionEvent.ACTION_CANCEL -> {
                        v.isPressed = false
                        if (!isCursorMode) {
                            // If we didn't move enough to trigger cursor, it's a click (Space)
                            v.performClick()
                        }
                        return true
                    }
                }
                return false
            }
        })

        // DELETE LOGIC
        val delKey = root.findViewById<View>(R.id.key_del)
        val deleteHandler = android.os.Handler(android.os.Looper.getMainLooper())
        val deleteRunnable = object : Runnable {
            override fun run() {
                handleDelete()
                deleteHandler.postDelayed(this, 50)
            }
        }

        // SWIPE TO DELETE LOGIC
        delKey.setOnTouchListener(object : View.OnTouchListener {
            var startX = 0f
            var isSwipeMode = false
            var cachedText = ""

            override fun onTouch(v: View, event: MotionEvent): Boolean {
                val ic = currentInputConnection ?: return false
                when(event.action) {
                    MotionEvent.ACTION_DOWN -> {
                        startX = event.rawX
                        isSwipeMode = false
                        // Cache text now to avoid lag during swipe
                        cachedText = ic.getTextBeforeCursor(1000, 0)?.toString() ?: ""

                        if (isHapticEnabled) v.performHapticFeedback(HapticFeedbackConstants.KEYBOARD_TAP)
                        if (isSoundEnabled) playSound(AudioManager.FX_KEYPRESS_DELETE)

                        handleDelete()
                        deleteHandler.postDelayed(deleteRunnable, 400)
                        v.isPressed = true
                        return true
                    }
                    MotionEvent.ACTION_MOVE -> {
                        val diff = event.rawX - startX
                        // Threshold: Swipe left by 60px to trigger selection mode
                        if (!isSwipeMode && diff < -60) {
                            isSwipeMode = true
                            deleteHandler.removeCallbacks(deleteRunnable) // Stop repeating delete
                        }

                        if (isSwipeMode) {
                            // Calculate how many words to select
                            val dist = -(event.rawX - startX)
                            // FRICTION: 75px per word
                            val wordCount = (dist / 75).toInt().coerceAtLeast(0)
                            var deleteLength = calculateSwipeDeleteLength(cachedText, wordCount)

                            // FIX: If the selection starts on a space, shrink it to preserve the space
                            // This ensures "I'm doing" -> Deleting "doing" leaves "I'm " instead of "I'm"
                            val relativeStart = cachedText.length - deleteLength
                            if (deleteLength > 0 && relativeStart >= 0 && relativeStart < cachedText.length) {
                                if (cachedText[relativeStart].isWhitespace()) {
                                    deleteLength--
                                }
                            }

                            // Select the text visually
                            val start = (cursorPos - deleteLength).coerceAtLeast(0)
                            ic.setSelection(start, cursorPos)
                            return true
                        }
                        return true
                    }
                    MotionEvent.ACTION_UP, MotionEvent.ACTION_CANCEL -> {
                        deleteHandler.removeCallbacks(deleteRunnable)
                        v.isPressed = false
                        if (isSwipeMode) {
                            // User released finger: Delete the selected text
                            ic.commitText("", 1)
                            isSwipeMode = false
                        }
                        return true
                    }
                }
                return false
            }
        })

        root.findViewById<View>(R.id.key_enter).setOnClickListener { sendEnter() }

        // CAPS LOCK LOGIC (Cycle: Off -> One-Shot -> Locked -> Off)
        val shift = root.findViewById<View>(R.id.key_shift)
        shift.setOnClickListener {
            if (isCapsLocked) {
                // 3. Was Locked -> Turn Off
                isCaps = false
                isCapsLocked = false
            } else if (isCaps) {
                // 2. Was Shifted -> Turn Locked
                isCapsLocked = true
                isCaps = true
            } else {
                // 1. Was Off -> Turn Shifted (One-Shot)
                isCaps = true
                isCapsLocked = false
            }
            updateCapsUI()
        }
    }

