private fun loadAmharicJson() {
    DebugLogger.log("DICT", "Starting Amharic Dictionary Load...")
    var count = 0
    try {
        val resId = context.resources.getIdentifier("amharic_dict", "raw", context.packageName)
        if (resId != 0) {
            context.resources.openRawResource(resId).use { inputStream ->
                // STREAMING PARSER to avoid OutOfMemoryError on large files
                val reader = android.util.JsonReader(inputStream.bufferedReader())
                reader.isLenient = true

                try {
                    // Handle root object or array
                    // Expected format: { "words": [...] } OR [...] 
                    if (reader.peek() == android.util.JsonToken.BEGIN_OBJECT) {
                        reader.beginObject()
                        while (reader.hasNext()) {
                            val name = reader.nextName()
                            if (name == "words") {
                                readWordsArray(reader) { w, f -> 
                                    insertTrie(w, f)
                                    count++
                                }
                            } else {
                                reader.skipValue()
                            }
                        }
                        reader.endObject()
                    } else if (reader.peek() == android.util.JsonToken.BEGIN_ARRAY) {
                        readWordsArray(reader) { w, f -> 
                            insertTrie(w, f)
                            count++
                        }
                    }
                } catch (e: Exception) {
                     DebugLogger.log("DICT_ERR", "Parse error: ${e.message}")
                } finally {
                    try { reader.close() } catch (e: Exception) {}
                }
            }
            DebugLogger.log("DICT", "Success! Loaded $count Amharic words.")
        } else {
            DebugLogger.log("DICT", "File 'amharic_dict.json' not found in raw resources.")
        }
    } catch (e: Exception) {
        DebugLogger.log("DICT_FATAL", "Failed to load dictionary: ${e.message}")
        e.printStackTrace()
    }
}

private fun readWordsArray(reader: android.util.JsonReader, onWord: (String, Long) -> Unit) {
    reader.beginArray()
    while (reader.hasNext()) {
        reader.beginObject()
        var word = ""
        var freq = 5000L
        while (reader.hasNext()) {
            when (reader.nextName()) {
                "word" -> word = reader.nextString()
                "freq", "frequency" -> freq = reader.nextLong()
                else -> reader.skipValue()
            }
        }
        reader.endObject()
        if (word.isNotEmpty()) onWord(word, freq)
    }
    reader.endArray()
}

