private fun pickSuggestion(suggestion: String) {
    val ic = currentInputConnection ?: return
    val text = ic.getTextBeforeCursor(100, 0)?.toString() ?: ""
    if (text.isEmpty()) return

    // 1. DETECT TRAILING SEPARATOR (e.g. "word.")
    var ignoreCount = 0
    var i = text.length - 1
    var separator = ""

    // Check if cursor is touching a separator
    if (i >= 0) {
        val lastChar = text[i].toString()
        if (separators.contains(lastChar)) {
            ignoreCount = 1
            separator = lastChar
            i--
        }
    }

