        // Allow apostrophe inside words but stop at anything else
        if (!c.isLetterOrDigit() && c != '\'') {
            break
        }
        i--
    }
    val start = i + 1

    // 3. IDENTIFY REPLACEMENT
    val effectiveEnd = text.length - ignoreCount
    if (start > effectiveEnd) {
