private fun setupPunctuationPopup(key: View) {
    val showRunnable = Runnable {
        showPunctuationWindow(key)
        // Haptic on open
        if (isHapticEnabled) key.performHapticFeedback(HapticFeedbackConstants.LONG_PRESS)
    }

    key.setOnTouchListener { v, event ->
        when (event.actionMasked) {
            MotionEvent.ACTION_DOWN -> {
                v.isPressed = true
                if (isHapticEnabled) v.performHapticFeedback(HapticFeedbackConstants.KEYBOARD_TAP)
                if (isSoundEnabled) playSound(AudioManager.FX_KEYPRESS_STANDARD)
                v.handler.postDelayed(showRunnable, 400)
                true
            }
            MotionEvent.ACTION_MOVE -> {
                if (punctuationPopupView != null) {
                     // Disallow parent interception (ScrollViews)
                     v.parent?.requestDisallowInterceptTouchEvent(true)
                     handlePunctuationSwipe(event)
                } else {
                     // Cancel long press if moved too far before triggering
                     // (Optional refinement, skipping for simplicity)
                }
                true
            }
            MotionEvent.ACTION_UP, MotionEvent.ACTION_CANCEL -> {
                v.handler.removeCallbacks(showRunnable)
                v.isPressed = false
                if (punctuationPopupView != null) {
                    // Commit Selection
                    val char = selectedPunctView?.text?.toString()
                    if (char != null) commit(char)
                    dismissPunctuationPopup()
                } else if (event.action == MotionEvent.ACTION_UP) {
                    // Standard Tap
                    commit(".")
                    updateSuggestions()
                }
                true
            }
            else -> false
        }
    }
}

private fun showPunctuationWindow(anchor: View) {
    val root = currentLayoutView as? ViewGroup ?: return

    // Inflate if needed
    val popup = layoutInflater.inflate(R.layout.popup_punctuation, root, false)
    punctuationPopupView = popup

    // Calculate Position
    // We want the Comma (Row 2, Index 6) to be centered over the Anchor
    // Grid is 8 columns. Comma is index 6 (0..7).
    val location = IntArray(2)
    anchor.getLocationInWindow(location)
    val rootLoc = IntArray(2)
    root.getLocationInWindow(rootLoc)

    val density = resources.displayMetrics.density
    val cellWidth = 44 * density
    val cellHeight = 44 * density

    // Anchor Center X relative to root
    val anchorCX = (location[0] - rootLoc[0]) + (anchor.width / 2f)
    val anchorTop = (location[1] - rootLoc[1])

    // Comma Center X in Popup: (6 * w) + (w/2) + padding(8dp)
    val commaCX = (8 * density) + (6 * cellWidth) + (cellWidth / 2f)

    val popupX = anchorCX - commaCX
    // Popup Y: Above anchor, shift up by height
    val popupY = anchorTop - (cellHeight * 2) - (16 * density) // 16dp padding total

    popup.translationX = popupX
    popup.translationY = popupY

    root.addView(popup)

    // Initial Selection: Comma
    // We manually trigger selection at the comma's location
    // Coordinates of comma center in popup
    handlePunctuationSwipeRaw(commaCX, (8 * density) + (cellHeight * 1.5f))
}

private fun handlePunctuationSwipe(event: MotionEvent) {
    val popup = punctuationPopupView ?: return
    // Map raw event to popup local coords
    val location = IntArray(2)
    popup.getLocationOnScreen(location)
    val localX = event.rawX - location[0]
    val localY = event.rawY - location[1]
    handlePunctuationSwipeRaw(localX, localY)
}

private fun handlePunctuationSwipeRaw(x: Float, y: Float) {
    val popup = punctuationPopupView as? ViewGroup ?: return

    // Flatten children to list
    val children = ArrayList<TextView>()
    // Row 1
    val row1 = popup.getChildAt(0) as ViewGroup
    for (i in 0 until row1.childCount) children.add(row1.getChildAt(i) as TextView)
    // Row 2
    val row2 = popup.getChildAt(1) as ViewGroup
    for (i in 0 until row2.childCount) children.add(row2.getChildAt(i) as TextView)

    // Hit Test
    var hit: TextView? = null
    var minDist = Float.MAX_VALUE

    for (child in children) {
        // Check simple bounds first? Or center distance?
        // Center distance is better for "magnetic" feel
        // Need child position relative to Popup
        val row = child.parent as ViewGroup
        val childX = row.x + child.x + (child.width / 2f)
        val childY = row.y + child.y + (child.height / 2f)

        val dist = Math.hypot((x - childX).toDouble(), (y - childY).toDouble()).toFloat()

        // Threshold: must be reasonably close (e.g. within 60dp)
        if (dist < minDist && dist < 150) {
            minDist = dist
            hit = child
        }
    }

    if (hit != selectedPunctView) {
        // Unselect old
        selectedPunctView?.background = null
        selectedPunctView?.setTextColor(0xFFFFFFFF.toInt())

        // Select new
        selectedPunctView = hit
        selectedPunctView?.setBackgroundResource(R.drawable.bg_punct_highlight)
        selectedPunctView?.setTextColor(0xFF202124.toInt())
    }
}

private fun dismissPunctuationPopup() {
    punctuationPopupView?.let { popup ->
        (popup.parent as? ViewGroup)?.removeView(popup)
    }
    punctuationPopupView = null
    selectedPunctView = null
}

