    `;

    try {
        console.log("[Surgeon] Prompt Prepared.");
        console.log("Error Summary:", summary);
        console.log("Diff Context:", changeContext);
        console.log("Files included:", contextFiles.map((c:any)=>c.path));

        const res = await fetch(OPENROUTER_URL, { 
